# 🧠 THE BIG PICTURE
# ══════════════════════════════════════════════════════════════════════════════
#
# In competitive programming, two things decide if you get AC (Accepted):
#   1. Your algorithm is correct.
#   2. Your code is fast enough within the time limit.
#
# • Python is beautiful but slow — roughly 5–10× slower than C++.
#   Bad I/O habits alone can turn an O(n) solution into TLE.
# • This chapter gives you the skeleton every Python CF submission should use.
#
# ══════════════════════════════════════════════════════════════════════════════
# 🔥 WHY FAST I/O MATTERS  [PY]

# ══════════════════════════════════════════════════════════════════════════════
#
# • Imagine reading 100,000 numbers.
# • Python's default input() is slow because it flushes buffers and does extra
#       work each call
# • sys.stdin.read() reads everything at once — one syscall instead of 100,000.
# • For n = 10^5 inputs, this difference can be AC vs TLE.
#
# 🎯 ONE LINE:
#   sys.stdin.buffer.read() is 10× faster than input() — always use it in Python CP
#
# 🔍 SIGNALS:
#   - "time limit exceeded"
#   - "large input"
#   - "n=10^5 lines"
#
# ❌ MISTAKES:
#   ✗ Using input() in a loop for n=10^5 → TLE even with correct O(n) algorithm
#   ✗ Forgetting to decode bytes: data=stdin.buffer.read().split() gives bytes not str → int(x) still works
#
#
# 🧠 THINKING:
#   1. What does brute force look like?
#   2. What is the complexity bottleneck?
#   3. What structure or property enables optimization?
#   → Code the optimized approach
#
# ══════════════════════════════════════════════════════════════════════════════
# ⚡ WHY wrap everything in solve()?
# ══════════════════════════════════════════════════════════════════════════════
#
# • Python accesses LOCAL variables faster than GLOBAL ones (CPython optimization).
# • Wrapping code in solve() makes all your variables local → measurable speedup.
# • It also keeps code clean and restartable for multiple test cases.

# 1A. THE UNIVERSAL CODEFORCES TEMPLATE (memorize this)

# import sys
# from collections import Counter, defaultdict, deque
# from math import gcd, isqrt
# from heapq import heappush, heappop
#
# def solve():
#     ...
#
# for _ in range(int(input())):
#     solve()
#
#   Python's default input() does additional work: flushes stdout buffers,
#   a direct read from the file descriptor. For 10^5 inputs, the difference
#   can literally mean AC vs TLE.
#
# because int() ignores whitespace. For strings, always use input().strip().
#
# 1B. COMPLETE INPUT PATTERN CATALOG

# These patterns cover 99% of all Codeforces I/O:
#
# Pattern 1: Single integer
# n = int(input())
#
# Pattern 2: Multiple integers on one line
# a, b, c = map(int, input().split())
#
# Pattern 3: Array of n integers
# a = list(map(int, input().split()))
#
# Pattern 4: Multiple test cases (most common format on CF)
# for _ in range(int(input())):
#     n = int(input())
#     a = list(map(int, input().split()))
#
# Pattern 5: Read until EOF (older CF problems / interactive)
# import sys
# for line in sys.stdin:
#     process(line.strip())
#
# Pattern 6: 2D grid / matrix
# n, m = map(int, input().split())
# grid = [list(map(int, input().split())) for _ in range(n)]
#
# Pattern 7: Fast bulk output (critical for problems printing many answers)
# out = []
# for _ in range(t):
#     out.append(str(answer))
# sys.stdout.write('\n'.join(out) + '\n')
#
# Pattern 8: Reading a string grid (maze problems)
# n, m = map(int, input().split())
# grid = [input().strip() for _ in range(n)]
#
# Pattern 9: Pairs / edges for graph problems
# n, m = map(int, input().split())
# adj = [[] for _ in range(n+1)]
# for _ in range(m):
#     u, v = map(int, input().split())
#     adj[u].append(v); adj[v].append(u)

# 1C. PYTHON NUMBERS — CRITICAL DIFFERENCES FROM C++

# OVERFLOW: Python integers have UNLIMITED precision. 2^1000 works perfectly.
# In C++: int is 32-bit (max ~2.1×10^9), long long is 64-bit (max ~9.2×10^18).
# Python bigints are SLOWER for enormous numbers. Use modular arithmetic.
#
# • DIVISION BEHAVIOR — THIS WILL CAUSE BUGS if you forget:
#     Python:  7 // 2 =  3  (floor division — rounds toward NEGATIVE INFINITY)
#     Python: -7 // 2 = -4  (rounds DOWN, not toward zero!)
#     C++:    -7  / 2 = -3  (integer division truncates toward zero)
#
#   Python: 7 % 3 = 1      (standard)
#           -7 % 3 = 2     (ALWAYS non-negative in Python!)
#   C++:    -7 % 3 = -1    (can be negative — dangerous for CP formulas)
#
# Python's modulo is actually mathematically correct (satisfies a = (a//b)*b + a%b).
# When porting code from C++ remember these differences!
#
# • FLOATING POINT: Avoid float in CP.
# • Use integer arithmetic wherever possible.
# • ceil(a/b) = (a + b - 1) // b  (exact integer, no floating point!) floor(a/b) =
#       a // b  (for positive a, b)

# 1D. ESSENTIAL MATH FORMULAS (O(1) building blocks)

# ┌────────────────────────────────────────────────────────────────────────────┐
# │ FORMULA                    │ CODE                        │ NOTES         │
# ├─────────────────────────────────────────────────────────────────────────────┤
# │ Sum 1..n                   │ n*(n+1)//2                  │ Gauss formula │
# │ Sum of squares 1..n        │ n*(n+1)*(2*n+1)//6          │               │
# │ Sum of cubes 1..n          │ (n*(n+1)//2)**2             │ = (sum 1..n)^2│
# │ Arithmetic series          │ k*(first+last)//2           │ k terms       │
# │ Geometric series (r≠1)     │ a*(r**n-1)//(r-1)           │ integer r only│
# │   ↳ use // only for integer r; (r-1) always divides (r^n-1) exactly so  │
# │     integer floor-division is safe. For float r use a*(r**n-1)/(r-1).   │
# │ Ceiling division           │ (a+b-1)//b                  │ NO float neede│
# │ Floor division             │ a//b                        │ positive only │
# │ Digits in n                │ len(str(n))                 │ Python trick  │
# │ Bit length of n            │ n.bit_length()              │ floor(log2 n) │
# │ Is n a perfect square?     │ isqrt(n)**2 == n            │ exact check   │
# └────────────────────────────────────────────────────────────────────────────┘

# 🧠 INTUITION:
#   • The ceiling division formula (a+b-1)//b is one of the most used
# tricks in CP. It comes from: "how many groups of b do I need to fit a items?"
# If a=10, b=3: need 4 groups (10/3=3.33..., round up → 4). Formula: (10+2)//3=4 ✓
#
# ══════════════════════════════════════════════════════════════════════════════
# 🧠 HOW A TOP CODER THINKS ABOUT I/O:
# ══════════════════════════════════════════════════════════════════════════════
#
# • "Before touching the algorithm, I establish my template.
# • Input reading is mechanical — get it right once, never think about it again.
# • Wrong I/O = WA even with a perfect algorithm.
# • And slow I/O = TLE on fast algorithms.".
#
# 🎯 ONE LINE:
#   sys.stdin.buffer.read() + output buffering are the two I/O habits that prevent TLE from day one
#
# 🔍 SIGNALS:
#   - "time limit exceeded"
#   - "large input"
#   - "n=10^5 lines"
#
# ❌ MISTAKES:
#   ✗ Using input() in a loop for n=10^5 → TLE even with correct O(n) algorithm
#   ✗ Forgetting to decode bytes: data=stdin.buffer.read().split() gives bytes not str → int(x) still works
#
#
# 🧠 THINKING:
#   1. What does brute force look like?
#   2. What is the complexity bottleneck?
