# ADVANCED DP PATTERNS — Rerooting, Profile DP, DP on DAGs
# ══════════════════════════════════════════════════════════════════════════════

# ── REROOTING DP ─────────────────────────────────────────────────────────────
# Problem: for each node v, compute f(v) = some function of the entire tree
#          when v is treated as the root. Example: sum of distances from v.
#
# Two-pass approach:
# Pass 1 (DFS down): compute dp_down[v] = answer rooted at v for subtree of v
# Pass 2 (DFS up):   compute dp_up[v] = contribution from the "other side"
#                    i.e., the tree minus v's subtree
#
# CANONICAL EXAMPLE: Sum of all pairwise distances in a tree
# dp_down[v] = sum of distances from v to all nodes in its subtree
# dp_up[v]   = sum of distances from v to all nodes NOT in its subtree
# answer[v]  = dp_down[v] + dp_up[v]
#
# Time: O(n)  Space: O(n)
#
# n = number of nodes (1-indexed); adj = adjacency list
subtree_sz=[1]*(n+1)
sum_down=[0]*(n+1)
parent=[-1]*(n+1)
order_rr=[]
reroot_stk=[1]
visited=[False]*(n+1)
visited[1]=True
while reroot_stk:
    v=reroot_stk.pop()
    order_rr.append(v)
    for u,_ in adj[v]:
        if not visited[u]:
            visited[u]=True
            parent[u]=v
            reroot_stk.append(u)
# Post-order: compute sz and dp_down
for v in reversed(order_rr):
    for u,_ in adj[v]:
        if u!=parent[v]:
            subtree_sz[v]+=subtree_sz[u]
            sum_down[v]+=sum_down[u]+subtree_sz[u]
# Pre-order: compute dp_up and final answer
sum_up=[0]*(n+1)
total_dist=[0]*(n+1)
for v in order_rr:
    total_dist[v]=sum_down[v]+sum_up[v]
    for u,_ in adj[v]:
        if u!=parent[v]:
            # dp_up[u] = contribution from v's side
            # = dp_up[v] + (dp_down[v] - dp_down[u] - sz[u]) + (n - sz[u])
            # = total_dist_v_from_above + v_to_rest_of_subtree + rest_count
            sum_up[u]=sum_up[v]+(sum_down[v]-sum_down[u]-subtree_sz[u])+(n-subtree_sz[u])
# answer_rr[v] = sum of distances from v to all other nodes
# For "minimum sum of distances": answer_rr[argmin(answer_rr[1:])]

# ── PROFILE DP (Broken-Profile DP) ───────────────────────────────────────────
# Problem: count ways to tile an m x n grid with 1x2 dominoes.
# State: dp[mask] = ways to fill columns up to current with profile `mask`
#        mask represents which cells in the CURRENT column are already filled
#        by a horizontal domino extending from the previous column.
#
# Time: O(n * m * 2^m)  Space: O(2^m)
# (Feasible for m <= 20, typically m <= 10 in practice)
#
# m = number of rows (small dimension), n = number of columns
# Result: number of ways to tile m x n grid with 1x2 dominoes
profile_dp=[0]*(1<<m)
profile_dp[0]=1
for col in range(n):
    new_dp=[0]*(1<<m)
    # Fill column `col` given incoming profile `mask`
    # Use DFS over rows to enumerate valid fillings
    profile_stk=[(0,0,profile_dp[:])]  # (row, new_mask, old_dp_copy) -- simplified
    # Standard implementation: iterate over all (old_mask, new_mask) pairs
    for old_mask in range(1<<m):
        if not profile_dp[old_mask]:
            continue
        # DFS to fill column top to bottom
        profile_stk=[(0,old_mask,0)]  # (row, prev_col_mask, cur_col_mask)
        while profile_stk:
            row,pmask,cmask=profile_stk.pop()
            if row==m:
                new_dp[cmask]=(new_dp[cmask]+profile_dp[old_mask])%(10**9+7)
                continue
            if pmask>>row&1:
                # Cell (row, col) already filled by horizontal from prev col
                profile_stk.append((row+1,pmask,cmask))
            else:
                # Option 1: place vertical domino (fills row and row+1 in this col)
                if row+1<m and not (pmask>>(row+1)&1):
                    profile_stk.append((row+2,pmask,cmask|(1<<row)|(1<<(row+1))))
                # Option 2: leave this cell for horizontal into next column
                profile_stk.append((row+1,pmask,cmask|(1<<row)))
                # Wait — "leave for horizontal" means set bit in new profile
                # Correction: leaving cell empty in current col means it will
                # need a horizontal domino going RIGHT -> set bit in cmask
    profile_dp=new_dp
tiling_count=profile_dp[0]
# result: _profile_result (number of valid tilings)

# ── DP ON DAG (Longest / Count Paths) ────────────────────────────────────────
# Problem: find longest path in a DAG, or count paths from s to t.
# Strategy: topological order DP. Process in topo order; propagate forward.
#
# Time: O(V + E)  Space: O(V)
#
# adj_dag = DAG adjacency list; n_dag = node count
# topo_dag = topological order (compute via Kahn's BFS)
indeg_dag=[0]*(n_dag+1)
for v in range(1,n_dag+1):
    for u,_ in adj_dag[v]:
        indeg_dag[u]+=1
from collections import deque as dag_q
qd=dag_q(v for v in range(1,n_dag+1) if indeg_dag[v]==0)
topo_dag=[]
while qd:
    v=qd.popleft()
    topo_dag.append(v)
    for u,w in adj_dag[v]:
        indeg_dag[u]-=1
        if indeg_dag[u]==0:
            qd.append(u)

# Longest path from any source:
dp_dag_len=[-1]*(n_dag+1)
for v in range(1,n_dag+1):
    if indeg_dag[v]==0:
        dp_dag_len[v]=0  # re-init (indeg_dag was modified above)
dp_dag_len=[0]*(n_dag+1)
for v in topo_dag:
    for u,w in adj_dag[v]:
        if dp_dag_len[v]+w>dp_dag_len[u]:
            dp_dag_len[u]=dp_dag_len[v]+w
longest_dag_path=max(dp_dag_len[1:n_dag+1])

# Count paths from source s_dag to sink t_dag (mod MOD):
count_dag=[0]*(n_dag+1)
count_dag[s_dag]=1
for v in topo_dag:
    for u,_ in adj_dag[v]:
        count_dag[u]=(count_dag[u]+count_dag[v])%MOD
# result: count_dag[t_dag]

# ── DP OPTIMIZATION SUMMARY ───────────────────────────────────────────────────
# When to use each DP speedup technique:
#
#   dp[i] = min over j<i of (dp[j] + cost(j,i))
#     cost is linear in i (cost = a[j]*x[i]+b[j])  -> CHT monotone O(n)
#     cost has monotone opt (opt(i)<=opt(i+1))      -> D&C DP O(n log n)
#     cost satisfies quadrangle inequality            -> Knuth O(n^2) from O(n^3)
#
#   count[mask] = sum over submasks                 -> SOS DP O(n * 2^n)
#   sum over all subsets of a mask                  -> SOS DP O(n * 2^n)
#
#   dp on intervals [l..r] of length 2..n           -> Interval DP O(n^3)
#   tile/fill grid problems (small rows)             -> Profile/broken-profile DP
#   re-root tree DP for all-node answers             -> Rerooting O(n)
#
# ══════════════════════════════════════════════════════════════════════════════
# 🔥 PRE-CHAPTER 7 — COMPLETE DYNAMIC PROGRAMMING THEORY  [DP]

# ══════════════════════════════════════════════════════════════════════════════
#
# §1. THE TWO FUNDAMENTAL PROPERTIES OF DP PROBLEMS
#
# ──────────────────────────────────────────────────────────────────────────────
# ──────────────────────────────────────────────────────────────────────────────
#
# §2. THE STATE DESIGN METHODOLOGY — HOW EXPERTS FORMULATE DP

# This is the hardest part of DP. Master this, and you can solve any DP problem.
#
# STEP 1: Identify what changes.
# • In a sequence problem: which index are we at? In a knapsack problem: which
#       items have been considered? What capacity remains? In a grid problem:
#       which cell are we at? In a game problem: whose turn is it? What's the
#       board state?
#
# STEP 2: Define dp[state] clearly.
#   "dp[i] = the [minimum/maximum/count] of [something] considering [first i items / prefix up to i]"
#   The state must COMPLETELY determine the answer (no hidden information).
#
# STEP 3: Write the recurrence.
# • "To compute dp[state], I must have made some 'last decision'." "What is the
#       set of possible last decisions?" "For each last decision d: dp[state] =
#       combine(dp[smaller state after d], cost(d))"
#
# STEP 4: Identify base cases.
#   The smallest states where the answer is trivially known.
#
# STEP 5: Determine computation order.
#   Ensure dp[state] is computed AFTER all states it depends on.
#   For 1D DP on sequences: usually left to right.
#   For 2D DP: row by row, left to right.
#   For interval DP: by length (short intervals before long ones).

# §3. THE SIX DP PATTERNS — COMPLETE CLASSIFICATION
#
# 🎯 ONE LINE:
#   DP = define state → write recurrence → handle base case → optimize if needed
#
# 🔍 SIGNALS:
#   - "minimize the maximum"
#   - "maximize the minimum"
#   - "minimum days"
#   - "fewest operations"
#   - "binary search on answer"
#   - "parametric search"
#
# ❌ MISTAKES:
#   ✗ Searching on array indices when you should search on answer values
#   ✗ check(mid) function is O(n²) making total O(n² log n) — optimize check() first
#
#
# 🧠 THINKING:
#   1. What is the state? (minimum info to solve subproblem)
#   2. What is the recurrence? (how to combine subproblems)
#   3. What is the base case?
#   → Define state precisely before writing any code
#
# ══════════════════════════════════════════════════════════════════════════════
# ⚡ PATTERN 1: LINEAR DP (1D state, sequence problems)  [DP]

# ══════════════════════════════════════════════════════════════════════════════
#
# • State: dp[i] = answer for prefix ending at index i.
# • Transition: dp[i] depends on dp[j] for j < i.
# • Examples: Fibonacci, coin change, climbing stairs, LIS (O(n²) version),.
#           Kadane's, house robber.
#
#
# 🧠 THINKING:
#   1. What is the brute force?
#   2. What is the bottleneck?
#   3. What structure enables the optimization?
#   → Code the optimized solution
#
# ══════════════════════════════════════════════════════════════════════════════
# ▶ DIAGRAM:
# ══════════════════════════════════════════════════════════════════════════════

#   dp:  [dp[0]] [dp[1]] [dp[2]] [dp[3]] ... [dp[n]]
#           ↑       ↑       ↑       ↑
#         base   ←from←  ←from←  ←from←
#
#   dp[i] ← dp[i-1] ← dp[i-2] ← …  (each state uses earlier states)
#
# TEMPLATE:
#   dp[0] = base_case
#   for i in range(1, n+1):
#       dp[i] = min/max/sum over all valid transitions from dp[j] (j < i)
#
# ══════════════════════════════════════════════════════════════════════════════
# 🧠 PATTERN 2: 2D DP (grid or two-sequence problems)  [DP]

# ══════════════════════════════════════════════════════════════════════════════
#
# State: dp[i][j] = answer for first i of sequence 1, first j of sequence 2
#                  OR answer for grid cell (i, j).
# Examples: Edit distance, LCS, unique paths, minimum path sum.
#
#
# 🧠 THINKING:
#   1. Can I reduce this to mod arithmetic?
#   2. Is the modulus prime? (enables Fermat inverse)
#   3. Do I need modular inverse for division?
#   → If dividing under mod → use pow(b, MOD-2, MOD)
#
# ══════════════════════════════════════════════════════════════════════════════
# ▶ DIAGRAM (Edit distance between "cat" and "hat"):
# ══════════════════════════════════════════════════════════════════════════════

#        ""   h    a    t
#   ""  [ 0][ 1][ 2][ 3]   ← base case: dp[0][j] = j (insert j chars)
#   c   [ 1][ 1][ 2][ 3]   ← dp[1][1]: c≠h → min(dp[0][0]+1, dp[0][1]+1, dp[1][0]+1)=1
#   a   [ 2][ 2][ 1][ 2]   ← dp[2][2]: a=a → dp[1][1] = 1
#   t   [ 3][ 3][ 2][ 1]   ← dp[3][3]: t=t → dp[2][2] = 1 (one substitution: c→h)
#
# 🎯 ONE LINE:
#   LCS/Edit distance: dp[i][j] built from dp[i-1][j-1] when chars match, else from neighbors
#
# 🔍 SIGNALS:
#   - "divisible by"
#   - "remainder when divided"
#   - "modulo"
#   - "last K digits"
#   - "periodic pattern"
#
# ❌ MISTAKES:
#   ✗ Doing (a*b)%m without wrapping a,b first → overflow in C++ (fine in Python but slow)
#   ✗ Subtracting mod: (a-b)%m can be negative → use (a-b+m)%m
#   ✗ Division mod p: a/b%p ≠ (a%p)/(b%p) → use modular inverse b^(p-2)%p
#
#
# 🧠 THINKING:
#   1. What does brute force look like?
#   2. What is the complexity bottleneck?
#   3. What structure or property enables optimization?
#   → Code the optimized approach
#
# ══════════════════════════════════════════════════════════════════════════════
# 💡 PATTERN 3: KNAPSACK DP (selection under constraints)  [DP]

# ══════════════════════════════════════════════════════════════════════════════
#
# Classic: dp[i][j] = max value using first i items with capacity j.
# Optimized 1D: dp[j] = max value with capacity j (rolling array).
#
# 0/1 KNAPSACK — each item used at most once:
#   dp[j] = max(dp[j], dp[j-w[i]] + v[i])
#   Iterate j DESCENDING (prevents using item i multiple times).
#
# UNBOUNDED KNAPSACK — items can repeat:
#   dp[j] = max(dp[j], dp[j-w[i]] + v[i])
#   Iterate j ASCENDING (allows using item i again after it's first used).
#
# ══════════════════════════════════════════════════════════════════════════════
# ▶ DIAGRAM — Why 0/1 knapsack needs descending iteration:  [DP]

# ══════════════════════════════════════════════════════════════════════════════

#   Item: w=2, v=5. Capacity W=6.
#   CORRECT (descending j=6,5,4,...):
#     j=6: dp[6] = max(dp[6], dp[4]+5)   ← dp[4] not yet updated this round ✓
#     j=4: dp[4] = max(dp[4], dp[2]+5)   ← dp[2] not yet updated ✓
#     (item used at most once per pass)
#
#   WRONG (ascending j=2,3,4,...):
# • j=2: dp[2] = max(dp[2], dp[0]+5) = 5   ← item used once, dp[2]=5 j=4: dp[4] =
#       max(dp[4], dp[2]+5) = 10  ← uses dp[2]=5 (updated this round!) This means
#       item was used TWICE
# • Wrong for 0/1 knapsack!.
#
# 🎯 ONE LINE:
#   0/1 knapsack: iterate capacity BACKWARDS — forward iteration allows item reuse
#
# 🔍 SIGNALS:
#   - "capacity constraint"
#   - "select items with weight limit"
#   - "at most W"
#   - "subset sum"
#
# ❌ MISTAKES:
#   ✗ Iterating w from 0 to W (forward) in 0-1 knapsack → each item used multiple times
#   ✗ Iterating w from W to 0 (backward) in unbounded knapsack → each item used once only
#   ✗ Off-by-one: dp has size W+1; index from 0 to W inclusive
#
#
# 🧠 THINKING:
#   1. What does brute force look like?
#   2. What is the complexity bottleneck?
#   3. What structure or property enables optimization?
#   → Code the optimized approach
#
# ══════════════════════════════════════════════════════════════════════════════
# 🎯 PATTERN 4: INTERVAL DP (splitting problems)  [DP]

# ══════════════════════════════════════════════════════════════════════════════
#
# • State: dp[l][r] = optimal answer for subproblem on interval [l, r].
#       Transition: dp[l][r] = min/max over split point m: dp[l][m] + dp[m+1][r] +
#       cost(l,r,m) Order: iterate by interval LENGTH (length 1 first, then 2,
#       ..., then n)
#
# Why length order? dp[l][r] depends on dp[l][m] and dp[m+1][r] which are SHORTER.
# Computing shorter intervals first ensures dependencies are ready.
#
# Examples: Matrix chain multiplication, Burst Balloons, Optimal BST,
#           Palindrome partitioning, Stone merging.
#
# ══════════════════════════════════════════════════════════════════════════════
# ▶ DIAGRAM (Matrix chain mult):
# ══════════════════════════════════════════════════════════════════════════════

#   Matrices: A₁(10×30), A₂(30×5), A₃(5×60)
# • dp[0][1]: split at
# • Cost = 10×30×5 = 1500.
# • dp[1][2]: split at
# • Cost = 30×5×60 = 9000.
# • dp[0][2]: Split at 0: 0+9000+10×30×60=9000+18000=27000.
# • Split at 1: 1500+0+10×5×60=1500+3000=4500.
# • dp[0][2] = min(27000, 4500) = 4500.
# • (A₁(A₂A₃) grouping).
#
# 🎯 ONE LINE:
#   Matrix expo: linear recurrence f(n)=af(n-1)+bf(n-2) → matrix^n in O(k³ log n)
#
# 🔍 SIGNALS:
#   - "nth Fibonacci"
#   - "linear recurrence"
#   - "large n"
#   - "state transition"
#   - "counting paths of length n"
#
# ❌ MISTAKES:
#   ✗ Matrix multiplication is O(k³) per multiply; total O(k³ log n) — k must be small
#   ✗ Not initializing the identity matrix correctly for matrix power
#   ✗ Applying this to non-linear recurrences → doesn't work; only linear recurrences
#
#
# 🧠 THINKING:
#   1. What does brute force look like?
#   2. What is the complexity bottleneck?
#   3. What structure or property enables optimization?
#   → Code the optimized approach
#
# ══════════════════════════════════════════════════════════════════════════════
# 🚀 PATTERN 5: BITMASK DP (subset/assignment problems, n ≤ 20)  [DP]

# ══════════════════════════════════════════════════════════════════════════════
#
# • State: dp[mask] or dp[mask][v] where mask = bitmask of selected/visited items.
# • Transition: add one more item/vertex to the mask.
# • Size: 2ⁿ states, each with n transitions = O(n·2ⁿ) total.
#
# Examples: TSP (Traveling Salesman), assignment problem, set cover.
#
# 🎯 ONE LINE:
#   Bitmask = integer representing subset; (mask>>i)&1 checks item i; mask|(1<<i) adds item i
#
# 🔍 SIGNALS:
#   - "n ≤ 20"
#   - "subset"
#   - "assign each element to group"
#   - "cover all"
#   - "traveling salesman"
#
# ❌ MISTAKES:
#   ✗ Iterating 2^n for n=25 → 33 million; for n=30 → 1 billion → TLE
#   ✗ Not initializing dp table: dp = [INF]*(1<<n); dp[0]=0 is the standard pattern
#   ✗ Forgetting that mask^(1<<i) REMOVES bit i only if bit i is already set — check first
#
#
# 🧠 THINKING:
#   1. What is the state? (minimum info to solve subproblem)
#   2. What is the recurrence? (how to combine subproblems)
#   3. What is the base case?
#   → Define state precisely before writing any code
#
# ══════════════════════════════════════════════════════════════════════════════
# 🔥 PATTERN 6: DIGIT DP (counting integers with digit constraints)  [DP]

# ══════════════════════════════════════════════════════════════════════════════
#
# Problem: Count integers in [0, N] with some property about their digits.
# State: dp[position][tight][extra_state]
# • position: current digit being decided (0 = most significant).
# • tight: are we still bounded by N's digits? (True = can't exceed N[position])
# • extra_state: whatever property we're tracking (sum of digits, count of zeros, etc.).
#
#
# 🧠 THINKING:
#   1. State: (pos, tight, [other needed info])
#   2. tight=True means we're still bounded by N's digits
#   3. When tight=True, max digit = N[pos]; else max digit = 9
#   → Use @cache on (pos, tight, ...) — top-down is cleaner
#
# ══════════════════════════════════════════════════════════════════════════════
# ▶ TRICK: "Tight constraint" — if tight=True, current digit ≤ N[position].
# ══════════════════════════════════════════════════════════════════════════════

#         Once we place a digit < N[position], tight becomes False (no more constraint).

# §4. TOP-DOWN vs BOTTOM-UP — DETAILED COMPARISON

# TOP-DOWN (Memoization):
# • Write the natural recursion.
# • Add a cache (dict or @lru_cache).
# • Compute only states actually needed (lazy evaluation).
# • Python: @lru_cache(maxsize=None) or manual dict memo.
#
# • Pros: Natural to write.
# • Only computes needed states.
# • Cons: Recursion overhead.
# • Python stack limit (default 1000).
# • Solution: sys.setrecursionlimit(300000) and increase stack.
#
# BOTTOM-UP (Tabulation):
#   Fill a table starting from base cases.
#   Use loops in dependency order.
#   No recursion overhead.
#
# • Pros: Faster (no function call overhead).
# • No stack issues.
# • Often allows space optimization (rolling array).
# • Cons: Must determine computation order explicitly.
# • Must initialize all states (even those not needed).
#
# ══════════════════════════════════════════════════════════════════════════════
# ▶ RULE FOR CP: Use bottom-up in Python for anything with n > 10⁴.
# ══════════════════════════════════════════════════════════════════════════════

#              Use top-down for complex state spaces or first drafts.

# §5. SPACE OPTIMIZATION TECHNIQUES

# TECHNIQUE 1: Rolling Array
#   If dp[i] only depends on dp[i-1] (and not dp[i-2], dp[i-3], …):
#   Use two 1D arrays: prev and curr. Or just two variables.
#
#   Fibonacci: a, b = b, a+b  (O(1) space instead of O(n))
#   Knapsack:  1D dp array iterated in reverse (see Pattern 3 above)
#
# • TECHNIQUE 2: Two-Row Rolling (for 2D DP depending on previous row) If dp[i][j]
#       only depends on dp[i-1][j], dp[i-1][j-1], dp[i][j-1]: Use dp[2][m] and
#       alternate rows with dp[i&1][j]
#   Space: O(m) instead of O(n×m).
#
# TECHNIQUE 3: Coordinate Compression
#   If dp values are sparse (only k distinct states), use a dict instead of array.
#   Space: O(k) instead of O(range of states).

# §6. RECONSTRUCTING THE SOLUTION (BACKTRACKING THROUGH DP)

# DP often asks "what is the optimal value?" but sometimes asks "what IS the
# optimal solution?" (Which items? Which path? Which partition?)
#
# • METHOD 1: Store the choice at each state.
# • parent[i] = j means "dp[i] was computed from dp[j] via choice c." After
#       computing dp, trace back: i → parent[i] → parent[parent[i]] → … → base
#
# METHOD 2: Recompute from dp values.
#   At each state, check which transition was used (which state matches dp[state] - cost).
#
# ══════════════════════════════════════════════════════════════════════════════
# ▶ EXAMPLE (LCS reconstruction):
# ══════════════════════════════════════════════════════════════════════════════

#   Fill dp[i][j]. Then backtrack:
# • If s[i]==t[j]: add s[i] to solution, move to dp[i-1][j-1]. Else: move to max(dp[i-1][j], dp[i][j-1]).
# • This gives the actual LCS string, not just its length.
#
# ══════════════════════════════════════════════════════════════════════════════
# 🧠 THE BIG PICTURE
# ══════════════════════════════════════════════════════════════════════════════
#
# DP = break a big problem into smaller subproblems, solve each ONCE, store the result.
# Next time that subproblem appears → look it up instead of recomputing. That's it.
#
# ══════════════════════════════════════════════════════════════════════════════
# 🧠 ANALOGY
# ══════════════════════════════════════════════════════════════════════════════
#
# • Computing Fibonacci naively: fib(5) calls fib(4) and fib(3).
# • fib(4) calls fib(3) and fib(2).
# • fib(3) is computed TWICE.
# • For fib(50), the same tiny subproblems get computed billions of times.
# • DP says: compute fib(3) once, write it down, never compute it again.
#
# ══════════════════════════════════════════════════════════════════════════════
# 💡 TWO PROPERTIES REQUIRED FOR DP  [DP]

# ══════════════════════════════════════════════════════════════════════════════
#
# 1. OPTIMAL SUBSTRUCTURE
# • The best solution to the big problem contains best solutions to subproblems.
# • Example: the shortest path from A to C through B = shortest(A→B) + shortest(B→C).
# • If this isn't true → DP won't work (example: longest simple path in a graph).
#
# 2. OVERLAPPING SUBPROBLEMS
#    The same subproblem shows up multiple times.
#    If all subproblems are unique → divide & conquer is better (no reuse benefit).
#
# 🎯 ONE LINE:
#   Two pointers: left/right from same or opposite ends — array MUST be sorted or monotone
#
# 🔍 SIGNALS:
#   - "pair with sum"
#   - "three sum"
#   - "count pairs"
#   - "sorted array + condition"
#
# ❌ MISTAKES:
#   ✗ Using two pointers on unsorted array → wrong answers
#   ✗ Moving both pointers in same direction when they should converge from opposite ends
#
#
# 🧠 THINKING:
#   1. What is the state? (minimum info to solve subproblem)
#   2. What is the recurrence? (how to combine subproblems)
#   3. What is the base case?
#   → Define state precisely before writing any code
#
# ══════════════════════════════════════════════════════════════════════════════
# 🎯 DP vs GREEDY  [DP]

# ══════════════════════════════════════════════════════════════════════════════
#
# • Greedy: make one locally-best choice, never look back.
# • DP: consider ALL choices at each step, take the best one — but reuse past work.
# • DP is slower (more states) but correct for problems where greedy fails.
#
# 🎯 ONE LINE:
#   Greedy = commit to locally best choice — prove correctness via exchange argument
#
# 🔍 SIGNALS:
#   - "minimum cost"
#   - "maximum items"
#   - "earliest deadline"
#   - "sort then pick"
#
# ❌ MISTAKES:
#   ✗ Applying greedy without proof → wrong answer on edge cases
#   ✗ Not sorting before greedy — most greedy algorithms require sorted input
#
#
# 🧠 THINKING:
#   1. What is the state? (minimum info to solve subproblem)
#   2. What is the recurrence? (how to combine subproblems)
#   3. What is the base case?
#   → Define state precisely before writing any code
#
# ══════════════════════════════════════════════════════════════════════════════
# ⚡ THE FORMULA FOR ANY DP  [DP]

# ══════════════════════════════════════════════════════════════════════════════
#
# dp[state] = best answer for the subproblem described by "state"
# dp[state] = combine(dp[smaller_state_1], dp[smaller_state_2], ...)
#
# Your ENTIRE job is to figure out:
#   • What is the STATE? (what varies across subproblems?)
#   • What is the TRANSITION? (how do smaller states combine?)
#   • What are the BASE CASES? (the smallest known answers?)
#
# DP IS NOT JUST MEMOIZATION. It's a way of THINKING.
# The real skill is defining the STATE and the TRANSITION correctly.
#
# ══════════════════════════════════════════════════════════════════════════════
# ▶ INTUITION ENGINE — How to "See" DP in a Problem  [DP]

# ══════════════════════════════════════════════════════════════════════════════

# Ask these questions when facing a new problem:
#   1. "What is the LAST DECISION made to reach the optimal solution?"
#      (This defines your DP transition.)
#   2. "What information do I need to describe my CURRENT STATE completely?"
#      (This defines your DP state dimensions.)
#   3. "What are the BASE CASES?"
#      (The smallest subproblems with known answers.)
#
# PROCESS FOR DEFINING DP STATE:
# • Step 1: Identify what changes as you process the input.
# • Step 2: Identify what you want to OPTIMIZE (maximize, minimize, count).
# • Step 3: State = (parameters describing what you've processed) + (constraints still active).
#   Step 4: Transition = for each decision you can make, how does the state change?

# ══════════════════════════════════════════════════════════════════════════════
# ▶ DP COMPLEXITY DECISION SYSTEM  [DP]

# ══════════════════════════════════════════════════════════════════════════════

# ┌────────────────────────────────────────────────────────────────────────────┐
# │ DP Pattern       │ State Space     │ Typical Complexity │ When Used      │
# ├─────────────────────────────────────────────────────────────────────────────┤
# │ 1D DP            │ O(n)            │ O(n) or O(n²)      │ sequences      │
# │ 2D DP            │ O(n²) or O(nm)  │ O(n²) to O(n²m)    │ two sequences/g│
# │ Knapsack         │ O(n×W)          │ O(n×W)             │ subset selectio│
# │ Bitmask DP       │ O(2^n × n)      │ O(2^n × n)         │ n ≤ 20, subsets│
# │ Interval DP      │ O(n²)           │ O(n³)              │ strings, matric│
# │ Tree DP          │ O(n)            │ O(n) to O(n²)      │ tree problems  │
# │ Digit DP         │ O(digits × state)│ O(log(n) × state) │ counting by dig│
# └────────────────────────────────────────────────────────────────────────────┘

# ══════════════════════════════════════════════════════════════════════════════
# ▶ TOP-DOWN vs BOTTOM-UP — When to Use Each
# ══════════════════════════════════════════════════════════════════════════════

# TOP-DOWN (Memoization + Recursion):
# • + Natural to write (follow the recurrence directly) + Only computes needed
#       states (good for sparse state spaces) - Recursion overhead (slower in
#       Python, stack limit issues) - Python recursion limit: 1000 by default
# • Add sys.setrecursionlimit(300000).
#
# BOTTOM-UP (Tabulation):
#   + No recursion overhead (faster in Python)
#   + No stack overflow
#   - Must compute ALL states in correct order
#   - Slightly harder to write for complex transitions
#
# RECOMMENDATION FOR CF IN PYTHON: Use bottom-up whenever possible.

# 7A. COIN CHANGE — The Archetypal DP

# Problem: Given coin denominations c[1..k], find minimum coins to make amount n.
#
# STATE: dp[i] = minimum coins to make amount i.
# BASE CASE: dp[0] = 0 (0 coins needed to make amount 0).
# TRANSITION: dp[i] = 1 + min(dp[i - c[j]]) for all coins c[j] ≤ i.
#             "Use one more coin c[j], then solve for i-c[j]."
#
# ══════════════════════════════════════════════════════════════════════════════
# ▶ ANSWER: dp[n].  [DP]

# ══════════════════════════════════════════════════════════════════════════════

# DRY RUN on coins=[1,3,4], n=6:
# dp[0]=0
# • dp[1]=1+min(dp[0])=1            (use coin 1: dp[0]+1=1) dp[2]=1+min(dp[1])=2
#       (use coin 1 twice) dp[3]=1+min(dp[2],dp[0])=1      (use coin 3: dp[0]+1=1)
#       dp[4]=1+min(dp[3],dp[1],dp[0])=1 (use coin 4: dp[0]+1=1)
#       dp[5]=1+min(dp[4],dp[2],dp[1])=2 (use coin 4+1 or 3+1+1)
#       dp[6]=1+min(dp[5],dp[3],dp[2])=2 (use coin 3+3: dp[3]+1=2) ✓
# 💡 NOTE:
#   • dp[6]=2 but greedy would give dp[4+1+1]=3. DP wins!
#
n, k=map(int, input().split())
c=list(map(int, input().split()))
INF=float('inf')
dp=[INF]*(n+1)
dp[0]=0
for i in range(1, n+1):
    for coin in c:
        if coin <= i and dp[i-coin] != INF:
            dp[i]=min(dp[i], dp[i-coin]+1)
print(dp[n] if dp[n] != INF else -1)
#
# COUNTING WAYS (instead of minimum):
# dp[i] += dp[i - coin] for each coin  (dp[0] = 1 as base)

# 7B. LONGEST INCREASING SUBSEQUENCE (LIS) — O(n²) DP + O(n log n) Patience Sort

# WHAT IS LIS?
# Longest strictly increasing subsequence (not necessarily contiguous).
# Example: [3,1,4,1,5,9,2,6] → LIS = [1,4,5,9] or [1,4,5,6] → length 4.
#
# O(n²) DP:
# • dp[i] = length of LIS ending at index i.
# • dp[i] = 1 + max(dp[j]) for all j < i where a[j] < a[i]. (The LIS ending at i
#       extends the longest LIS ending at some j < i.)
#
# DRY RUN on [3,1,4,1,5,9,2,6]:
# dp[0]=1 (just 3)
# dp[1]=1 (just 1; 3>1 so can't extend)
# dp[2]=2 (1,4: dp[1]+1=2; also dp[0]+1=2 since 3<4; both agree)
# dp[3]=1 (1; only element ≤ all previous is itself, but 3>1,4>1,1=1 not strict)
# dp[4]=3 (1,4,5: dp[2]+1=3)
# dp[5]=4 (1,4,5,9: dp[4]+1=4)
# dp[6]=2 (1,2: dp[1]+1=2; dp[3]+1=2)
# dp[7]=3 (1,4,6: dp[2]+1=3 since 4<6; or 1,2,6: dp[6]+1=3)
# LIS length = max(dp) = 4 ✓
#

# ── lis_n2 — inline ──
# result→lis_len
#
# 🎯 ONE LINE:
#   LIS O(n²): dp[i] = LCS length ending at i — use for n ≤ 5000.
#
# 🔍 SIGNALS:
#   - "longest increasing subsequence" with n ≤ 5000
#   - "minimum deletions to sort" = n − LIS
#
# ❌ MISTAKES:
#   ✗ Initialising dp[i]=0 instead of 1 (each element is its own LIS of length 1)
#   ✗ Using O(n²) when n=10^5 → TLE; use patience sort O(n log n)
#   ✗ > vs >= for strict vs non-strict increasing
#
# 🧠 THINKING:
#   1. dp[i] = 1 + max(dp[j]) for j<i where a[j]<a[i].
#   2. Answer = max(dp).
#
# CF TAGS: dp, sequences  |  Rating: 1200–1600

#
# O(n log n) — Patience Sorting Trick
# Maintain list `tails` where tails[k] = smallest tail element of LIS of length k+1.
# For each element x:
# • If x > all tails → extend LIS by 1, append x.
# • Else → replace tails[bisect_left(tails, x)] = x (maintain optimal tails).
# • Length of `tails` at end = LIS length.
#
# ══════════════════════════════════════════════════════════════════════════════
# ▶ WHY DOES REPLACING WORK?
# ══════════════════════════════════════════════════════════════════════════════

# • We keep the SMALLEST possible tail for each LIS length.
# • This maximizes the chance of extending the LIS later with future elements.
# • The tails array is always sorted (invariant), so we can binary search it.
#
# DRY RUN on [3,1,4,1,5,9,2,6]:
# x=3: tails=[] → append. tails=[3]
# x=1: bisect_left([3],1)=0 → replace. tails=[1]
# x=4: 4>1 → append. tails=[1,4]
# x=1: bisect_left([1,4],1)=0 → replace. tails=[1,4]
# x=5: 5>4 → append. tails=[1,4,5]
# x=9: 9>5 → append. tails=[1,4,5,9]
# x=2: bisect_left([1,4,5,9],2)=1 → replace. tails=[1,2,5,9]
# x=6: bisect_left([1,2,5,9],6)=3 → replace. tails=[1,2,5,6]
# LIS length = len(tails) = 4 ✓
#
from bisect import bisect_left
#

# ── lis_nlogn — inline ──
# result→lis_len
#
# 🎯 ONE LINE:
#   Patience sort: tails[i] = smallest tail of all length-(i+1) increasing subsequences — O(n log n).
#
# 🔍 SIGNALS:
#   - "LIS with n up to 10^5"
#   - "minimum number of patience sorting piles"
#
# ❌ MISTAKES:
#   ✗ bisect_right instead of bisect_left → non-decreasing LIS (not strict)
#   ✗ Thinking tails IS the LIS — it's not; use parent pointers to reconstruct
#   ✗ Non-decreasing variant: replace bisect_left with bisect_right
#
# 🧠 THINKING:
#   1. tails[i] = smallest tail of LIS with length i+1.
#   2. For each x: binary search for first tail ≥ x; replace.
#   3. len(tails) = LIS length.
#
# CF TAGS: dp, binary search, sequences  |  Rating: 1400–1900

#
# For non-strict (≤): use bisect_right instead of bisect_left.
#
