# 8B. SLIDING WINDOW — Fixed and Variable Size

# FIXED WINDOW: Sum / max / min of every window of size k.
#

# ── fixed_window_sum — inline ──
# Time: O(n) | Space: O(n) output
result=[]
ws=sum(a[:k])
result.append(ws)
for i in range(k,len(a)):
    ws+=a[i]-a[i-k]
    result.append(ws)
# result→result
#
# • VARIABLE WINDOW: Minimum window satisfying a condition.
# • Pattern: expand right pointer until condition met, then shrink left until broken.
# • This finds all minimal windows satisfying the condition.
#

# ── min_window_sum_at_least_k — inline ──
count_n=len(a)
pre=[0]*(count_n+1)
for i in range(count_n):
    pre[i+1]=pre[i]+a[i]
from collections import deque as dq
min_dq=dq()
min_len=float("inf")
for i in range(count_n+1):
    while min_dq and pre[i]-pre[min_dq[0]]>=k:
        z_left=i-min_dq.popleft()
        if z_left<min_len:
            min_len=z_left
    while min_dq and pre[i]<=pre[min_dq[-1]]:
        min_dq.pop()
    min_dq.append(i)
# result→_ml
#
# ┌────────────────────────────────────────────────────────────────────────────┐
    # Minimum subarray length with sum >= k (all positive elements).
# └────────────────────────────────────────────────────────────────────────────┘
#
    n=len(a)
    lo=0
    window_sum=0
    min_len=float('inf')
    for hi in range(n):
        window_sum += a[hi]
        while window_sum >= k:
            min_len=min(min_len, hi-lo+1)
            window_sum -= a[lo]
            lo += 1
    # return min_len if min_len != float('inf') else -1
#

# ── longest_subarray_with_at_most_k_distinct — inline ──
freq={}
lo=0
best=0
for r_idx,x in enumerate(a):
    freq[x]=freq.get(x,0)+1
    while len(freq)>k:
        leaving=a[lo]
        freq[leaving]-=1
        if freq[leaving]==0:
            del freq[leaving]
        lo+=1
    if r_idx-lo+1>best:
        best=r_idx-lo+1
# result→_best
#
# ┌────────────────────────────────────────────────────────────────────────────┐
    # Longest subarray with at most k distinct elements.
# └────────────────────────────────────────────────────────────────────────────┘
#
    lo=0
    freq=defaultdict(int)
    result=0
    for hi in range(len(a)):
        freq[a[hi]] += 1
        while len(freq) > k:
            freq[a[lo]] -= 1
            if freq[a[lo]] == 0:
                del freq[a[lo]]
            lo += 1
        result=max(result, hi-lo+1)
    # return result

# 8C. PREFIX SUMS — Enabling O(1) Range Queries

# Prefix sums: pre[i] = a[0] + a[1] + ... + a[i-1].
# Range sum [l,r]: pre[r+1] - pre[l].  O(1) query after O(n) build.
#
# This is the SIMPLEST example of preprocessing for range queries.
# Use when: no updates, just range sum queries.
#

# ── prefix_sum_setup — inline ──
# result→pre
#
# 🎯 ONE LINE:
#   Prefix sums: build O(n), answer range sum O(1) — the most fundamental DS in CP.
#
# 🔍 SIGNALS:
#   - "sum of subarray [l..r]"
#   - "subarray with sum k" (hash map + prefix)
#   - "equilibrium/pivot index"
#
# ❌ MISTAKES:
#   ✗ Off-by-one: sum[l..r] = pre[r+1]-pre[l], not pre[r]-pre[l-1]
#   ✗ pre[0]=a[0] instead of pre[0]=0 → formula breaks
#   ✗ Loop-recomputing sum when O(1) prefix query would work
#
# 🧠 THINKING:
#   1. pre[i] = a[0]+...+a[i-1]. Build O(n).
#   2. sum(a[l..r]) = pre[r+1]-pre[l]. Query O(1).
#
# CF TAGS: prefix sums, arrays  |  Rating: 800–1300

#

# ── range_sum — inline ──
range_sum=pre[r+1]-pre[l]
# result→_rs
#
# 2D PREFIX SUMS (for grid queries):
#
#

# ── build_2d_prefix — inline ──
n_rows=len(grid)
n_cols=len(grid[0])
pre=[[0]*(n_cols+1) for _ in range(n_rows+1)]
for i in range(1,n_rows+1):
    for j in range(1,n_cols+1):
        pre[i][j]=grid[i-1][j-1]+pre[i-1][j]+pre[i][j-1]-pre[i-1][j-1]
# result→pre
#

# ── rectangle_sum — inline ──
rect_sum=pre[r2+1][c2+1]-pre[r1][c2+1]-pre[r2+1][c1]+pre[r1][c1]
# result→_rect
#
# 🎯 ONE LINE:
#   2D prefix sum: pre[r][c] = sum of rectangle (1,1)→(r,c); query any sub-rectangle in O(1)
#
# 🔍 SIGNALS:
#   - "which algorithm"
#   - "how to choose"
