# ── PARALLEL BINARY SEARCH ────────────────────────────────────────────────────
# Use when: you have Q independent binary searches and each check requires
#           processing a sequence of events — batch all checks together.
# Example: for each query q, find minimum time t such that check(q, t) is True.
#
# Time: O((n + Q) * log(MAX_T)) | Space: O(Q)
#
# queries = list of (lo, hi) initial bounds for each of Q queries
# check(events_up_to_t, q) = True/False for query q at time t
#
# Q = number of queries; MAX_T = search space size
pbs_lo = [0]*Q_pbs
pbs_hi = [MAX_T_pbs]*Q_pbs
pbs_ans = [MAX_T_pbs]*Q_pbs
for _ in range(MAX_T_pbs.bit_length() + 1):
    time_buckets = {}  # mid -> list of query indices
    for qi in range(Q_pbs):
        if pbs_lo[qi] < pbs_hi[qi]:
            mid = (pbs_lo[qi] + pbs_hi[qi]) // 2
            if mid not in time_buckets:
                time_buckets[mid] = []
            time_buckets[mid].append(qi)
    if not time_buckets:
        break
    # Process events up to each mid in sorted order
    event_ptr = 0
    for mid in sorted(time_buckets):
        # Process all events with time <= mid
        while event_ptr < len(events_pbs) and events_pbs[event_ptr][0] <= mid:
            # apply event to data structure
            event_ptr += 1
        for qi in time_buckets[mid]:
            if check_pbs(qi):  # feasibility check defined by user
                pbs_hi[qi] = mid
                pbs_ans[qi] = mid
            else:
                pbs_lo[qi] = mid + 1
    # Reset data structure for next iteration
# _pbs_ans[qi] = minimum t for query qi

