#
# PROBLEM 12-1 [Easy]: Count Connected Components
#

# ── count_components — inline ──
visited=[False]*(n+1)
comp_count=0
for start in range(1,n+1):
    if not visited[start]:
        comp_count+=1
        stk=[start]
        visited[start]=True
        while stk:
            v=stk.pop()
            for u,_ in adj[v]:
                if not visited[u]:
                    visited[u]=True
                stk.append(u)
# result→_cc
#
# • PROBLEM 12-2 [Medium]: Shortest Path in 0-1 BFS (edges weight 0 or 1) Use
#       deque: weight 0 → push front (popleft), weight 1 → push back (append)
# • This is O(V+E) — faster than Dijkstra!.
#

# ── bfs_01 — inline ──
from collections import deque as dq
INF=float("inf")
dist=[INF]*(n+1)
dist[start]=0
bfs01_q=dq([start])
while bfs01_q:
    v=bfs01_q.popleft()
    for u,w in adj[v]:
        if dist[v]+w<dist[u]:
            dist[u]=dist[v]+w
            if w==0:
                bfs01_q.appendleft(u)
            else:
                bfs01_q.append(u)
# result→dist
#
# PROBLEM 12-3 [Hard]: Flood Fill (count size of connected component in grid)
# Standard BFS/DFS from a start cell, marking visited.
#
# PROBLEM 12-4 [Hard]: Minimum Spanning Tree using BFS (for unit-weight graphs)
# BFS gives shortest path tree = MST for unit-weight graphs.
