# 14B. TREE DIAMETER — Longest Path (Two-BFS Trick)

# DIAMETER = length of longest path between any two vertices.
#
# ALGORITHM (beautifully simple!):
# 1. BFS from any vertex v. Find the FARTHEST vertex u from v.
# 2. BFS from u. Find the farthest vertex w from u.
# 3. Diameter = dist(u, w).
#
# WHY DOES THIS WORK?
# • Key theorem (proof by contradiction): The farthest vertex from ANY vertex
#   in a tree is always one endpoint of a diameter path.
# • Proof: Assume farthest from v is not on any diameter.
# • Let the diameter be (s, t).
# • The path from v to u must be ≥ path from v to t (since u is farthest).
# • This leads to a path s→...→u longer than diameter.
# • Contradiction.
#

# ── bfs_farthest — inline ──
from collections import deque as bfs_q
dist_bf=[-1]*(n+1)
dist_bf[start]=0
bfs_queue=bfs_q([start])
farthest_node=start
while bfs_queue:
    v=bfs_queue.popleft()
    if dist_bf[v]>dist_bf[farthest_node]:
        farthest_node=v
    for u,_ in adj[v]:
        if dist_bf[u]==-1:
            dist_bf[u]=dist_bf[v]+1
        bfs_queue.append(u)
# _far→farthest node; dist_bf→distances
#
# u, _ = bfs_farthest(1, adj_tree, n_tree)
# _, diameter = bfs_farthest(u, adj_tree, n_tree)
