# 14C. LOWEST COMMON ANCESTOR (LCA) — Binary Lifting

# WHAT IS LCA?
# • LCA(u, v) = deepest vertex that is an ancestor of BOTH u and v.
# • Example: in tree rooted at 1, with edges 1-2-4-5 and 1-3-6: LCA(4,5)=4 if 4 is
#       ancestor of 5
#
# ┌────────────────────────────────────────────────────────────────────────────┐
# │                                 🚀 APPLICATIONS                           │
# └────────────────────────────────────────────────────────────────────────────┘

# • Distance between two vertices: dist(u,v) = depth[u] + depth[v] - 2×depth[LCA(u,v)]
# • Checking if u is ancestor of v: LCA(u,v)==u
# • Path queries on trees (combine with Euler tour + BIT/segment tree)
#
# BINARY LIFTING: O(n log n) preprocessing, O(log n) per query.
# up[k][v] = the 2^k-th ancestor of v.
# up[0][v] = parent[v]
# up[k][v] = up[k-1][up[k-1][v]]  (2^k ancestor = apply 2^(k-1) twice)
#
# To find LCA(u,v):
# 1. Bring deeper vertex up to same depth (binary representation of depth diff).
# 2. If equal → that's LCA.
# 3. Otherwise lift both by largest 2^k that keeps them unequal.
# 4. Their parents = LCA.
#
# WHY BINARY? Binary representation means we need at most log n steps.
# "Jumping" by 2^k, 2^(k-1), ... mirrors binary number decomposition.
#
LOG=18
#
n_lca=int(input())
adj_lca=[[] for _ in range(n_lca+1)]
for _ in range(n_lca-1):
    u, v=map(int, input().split())
    adj_lca[u].append(v)
    adj_lca[v].append(u)
#
dep_lca=[0]*(n_lca+1)
up_lca=[[0]*(n_lca+1) for _ in range(LOG)]
#

# ── dfs_lca_setup — inline ──
# Time: O(n log n) build | O(log n) query | Space: O(n log n)
# Iterative binary lifting LCA setup
# Fills: anc[0][v]=parent, depth[v]; anc[k][v]=2^k-th ancestor
LOG=18
lca_stk=[(v,p,d)]
anc=[[0]*(n+1) for _ in range(LOG)]
depth=[0]*(n+1)
visited=[False]*(n+1)
visited[v]=True
while lca_stk:
    node,parent,depth=lca_stk.pop()
    depth[node]=depth
    anc[0][node]=parent
    for num_bits,_ in adj[node]:
        if not visited[num_bits]:
            visited[num_bits]=True
        lca_stk.append((num_bits,node,depth+1))
for k in range(1,LOG):
    for node in range(1,n+1):
        anc[k][node]=anc[k-1][anc[k-1][node]]
#
dfs_lca_setup(1, 0, 0)
for k in range(1, LOG):
    for v in range(1, n_lca+1):
        up_lca[k][v]=up_lca[k-1][up_lca[k-1][v]]
#

# ── lca_query — inline ──
# Time: O(log n) | Space: O(1) (uses precomputed anc/depth)
# u,v=nodes; anc=binary lifting table; depth=depth array
# Returns LCA of u and v
LOG=18
if depth[u]<depth[v]:
    u,v=v,u
depth_diff=depth[u]-depth[v]
for k in range(LOG):
    if depth_diff>>k&1:
        u=anc[k][u]
if u==v:
    lca_node=u
else:
    for k in range(LOG-1,-1,-1):
        if anc[k][u]!=anc[k][v]:
            u=anc[k][u]
        v=anc[k][v]
    lca_node=anc[0][u]
# result→_lca
#

# ── tree_distance — inline ──
# u,v=nodes using LCA; depth and anc must be precomputed
LOG=18
uu,vv=u,v
if depth[uu]<depth[vv]:
    uu,vv=vv,uu
depth_diff=depth[uu]-depth[vv]
for k in range(LOG):
    if depth_diff>>k&1:
        uu=anc[k][uu]
if uu!=vv:
    for k in range(LOG-1,-1,-1):
        if anc[k][uu]!=anc[k][vv]:
            uu=anc[k][uu]
        vv=anc[k][vv]
    lca_node=anc[0][uu]
else:
    lca_node=uu
tree_dist=depth[u]+depth[v]-2*depth[lca_node]
# result→_td
# 14D. TREE DP — Aggregating Information Over Subtrees

# Tree DP = DP where states are nodes of a tree, computed bottom-up.
# For each node, compute dp[v] from dp[children of v].
#
# CLASSIC: Maximum Independent Set on a Tree
# • Select subset of vertices (no two adjacent) to maximize count.
# • dp[v][0] = max set size in subtree of v, if v is NOT selected.
# • dp[v][1] = max set size in subtree of v, if v IS selected.
#
# TRANSITION:
# If v is selected (dp[v][1] = 1 + sum of dp[c][0] for children c):
#   Children cannot be selected.
# If v is not selected (dp[v][0] = sum of max(dp[c][0], dp[c][1]) for children c):
#   Children can be either selected or not.
#

# ── tree_independent_set — inline ──
dp=[[0,0] for _ in range(n+1)]
parent=[-1]*(n+1)
post_order=[]
indep_stk=[1]
visited=[False]*(n+1)
visited[1]=True
while indep_stk:
    v=indep_stk.pop()
    post_order.append(v)
    for u,_ in adj[v]:
        if not visited[u]:
            visited[u]=True
        parent[u]=v
        indep_stk.append(u)
for v in reversed(post_order):
    dp[v][1]=1
    for u,_ in adj[v]:
        if u!=parent[v]:
            dp[v][0]+=max(dp[u][0],dp[u][1])
        dp[v][1]+=dp[u][0]
max_indep_set=max(dp[1][0],dp[1][1])
# result→_tis
#

# PRACTICE PROBLEMS — TREES

# PROBLEM 14-1 [Easy]: Print all paths from root to leaves
# DFS maintaining current path. At leaf: print path.
#
# • PROBLEM 14-2 [Medium]: Centroid of a Tree
#   Centroid: vertex whose removal leaves components each of size ≤ n/2.
# • Every tree has 1 or 2 centroids.
# • Find by tracking subtree sizes.
#

# ── find_centroid — inline ──
subtree_sz=[1]*(n+1)
parent=[-1]*(n+1)
centroid_order=[]
cent_stk=[1]
visited=[False]*(n+1)
visited[1]=True
while cent_stk:
    v=cent_stk.pop()
    centroid_order.append(v)
    for u,_ in adj[v]:
        if not visited[u]:
            visited[u]=True
        parent[u]=v
        cent_stk.append(u)
for v in reversed(centroid_order):
    if parent[v]!=-1:
        subtree_sz[parent[v]]+=subtree_sz[v]
centroid=1
for v in centroid_order:
    ok=all(subtree_sz[u]<=n//2 for u,_ in adj[v] if u!=parent[v]) and n-subtree_sz[v]<=n//2
    if ok:
        centroid=v
    break
# result→centroid
