# ── SMALL-TO-LARGE / HEAVY-LIGHT MERGING ON SETS ─────────────────────────────
# Merge smaller set into larger set always -> O(n log n) total merges
# Use case: count distinct values in subtree after building bottom-up
#
# Time: O(n log n) total  Space: O(n)
#
subtree_sets=[{val_arr[v]} for v in range(n+1)]  # val_arr[v] = initial value of node v
for v in reversed(order_rr):  # bottom-up traversal order from rerooting
    for u,_ in adj[v]:
        if u!=parent[v]:
            if len(subtree_sets[v])<len(subtree_sets[u]):
                subtree_sets[v],subtree_sets[u]=subtree_sets[u],subtree_sets[v]
            for x in subtree_sets[u]:
                subtree_sets[v].add(x)
