# ── build_hld — inline ──
# Iterative Heavy-Light Decomposition
# Fills: parent,depth,heavy,head,pos arrays
subtree_sz=[1]*(n+1)
parent=[0]*(n+1)
depth=[0]*(n+1)
heavy=[-1]*(n+1)
head=[0]*(n+1)
pos=[0]*(n+1)
# Post-order for subtree sizes and heavy child
stack=[(root,-1,False)]
while stack:
    v,p,post_order=stack.pop()
    if post_order:
        mx=0
        for u,_ in adj[v]:
            if u!=parent[v]:
                subtree_sz[v]+=subtree_sz[u]
                if subtree_sz[u]>mx:
                    mx=subtree_sz[u]
                heavy[v]=u
    else:
        parent[v]=p
        stack.append((v,p,True))
        for u,_ in adj[v]:
            if u!=p:
                depth[u]=depth[v]+1
            stack.append((u,v,False))
# Assign HLD positions
cur_pos=0
stack=[(root,root)]
while stack:
    v,h=stack.pop()
    head[v]=h
    pos[v]=cur_pos
    cur_pos+=1
    for u,_ in adj[v]:
        if u!=parent[v] and u!=heavy[v]:
            stack.append((u,u))
    if heavy[v]!=-1:
        stack.append((heavy[v],h))
# pos[v]=position in seg tree; head[v]=chain head
#
# ┌────────────────────────────────────────────────────────────────────────────┐
    # DFS1: compute sz and heavy child iteratively
# └────────────────────────────────────────────────────────────────────────────┘
#
#
    order=[]
    visited=[False]*(n+1)
    stack=[root]
    visited[root]=True
    while stack:
        v=stack[-1]
        pushed=False
        for u in adj[v]:
            if not visited[u]:
                visited[u]=True
                parent[u]=v
                depth[u] =depth[v]+1
                stack.append(u)
                pushed=True
                break
        if not pushed:
            order.append(stack.pop())
#
    for v in order:
        for u in adj[v]:
            if u == parent[v]:
                continue
            subtree_sz[v] += subtree_sz[u]
            if heavy[v] == -1 or subtree_sz[u] > subtree_sz[heavy[v]]:
                heavy[v]=u
#
# ┌────────────────────────────────────────────────────────────────────────────┐
    # DFS2: assign chain heads and flattened positions
# └────────────────────────────────────────────────────────────────────────────┘
#
#
    head=[0]*(n+1)
    pos=[0]*(n+1)
    cur=[0]
    stack=[(root, root)]
    while stack:
        v, h=stack.pop()
        head[v]=h
        pos[v] =cur[0]
        cur[0] += 1
#
# ┌────────────────────────────────────────────────────────────────────────────┐
        # Process light children first (so heavy child is processed last = next in pos)
# └────────────────────────────────────────────────────────────────────────────┘
#
#
        for u in adj[v]:
            if u == parent[v] or u == heavy[v]:
                continue
            stack.append((u, u))
        if heavy[v] != -1:
            stack.append((heavy[v], h))
#
    # return parent, depth, heavy, head, pos, cur[0]
#

# ── path_query_hld — inline ──
# Query path u->v using HLD; seg_query(l,r) = range query on pos array
result=0  # identity; change for max/min
while head[u]!=head[v]:
    if depth[head[u]]<depth[head[v]]:
        u,v=v,u
    result=max(result,seg_query(pos[head[u]],pos[u]))
    u=parent[head[u]]
if depth[u]>depth[v]:
    u,v=v,u
result=max(result,seg_query(pos[u],pos[v]))
# result→result
