# ── centroid_decomp — inline ──
# Iterative centroid decomposition
subtree_sz=[1]*(n+1)
cent_parent=[-1]*(n+1)
removed=[False]*(n+1)
# get_subtree_size — inlined into centroid_decomp above
# get_centroid — inlined into centroid_decomp above
work_stack=[(1,-1)]
centroids=[]
while work_stack:
    v,prime=work_stack.pop()
    matrix_size=get_subtree_size(v,prime,n)
    c=get_centroid(v,prime,matrix_size[v],matrix_size)
    cent_parent[c]=prime
    centroids.append(c)
    removed[c]=True
    for u,_ in adj[c]:
        if not removed[u]:
            work_stack.append((u,c))
# centroids=decomposition order; par_cd=centroid parent
#
    def get_sz(v, p):
        subtree_sz[v]=1
        for u in adj[v]:
            if u != p and not removed[u]:
                get_sz(u, v)
                subtree_sz[v] += subtree_sz[u]
#
    def get_centroid(v, p, tree_sz):
        for u in adj[v]:
            if u != p and not removed[u]:
                if subtree_sz[u] > tree_sz//2:
                    return get_centroid(u, v, tree_sz)
        return v
#
    def decompose(v, par):
        get_sz(v, -1)
        c=get_centroid(v, -1, subtree_sz[v])
        centroid_par[c]=par
        removed[c]=True
        for u in adj[c]:
            if not removed[u]:
                decompose(u, c)
#
    decompose(1, -1)
