# HOW TO USE CENTROID DECOMP FOR PATH COUNTING:
# For each centroid c, collect distances from c to all nodes in its component.
# Count pairs: for each node at distance d from c, add to answer all nodes
#   at distance (target - d) already seen.
# Subtract over-counting: distances within the SAME subtree of c.

# ── small_to_large — inline ──
# Small-to-large merging on tree
# values[v]=initial value set for node v
merged=[set([values[v]]) for v in range(n+1)]
order=[]
parent=[-1]*(n+1)
stack=[root]
visited=[False]*(n+1)
visited[root]=True
while stack:
    v=stack.pop()
    order.append(v)
    for u,_ in adj[v]:
        if not visited[u]:
            visited[u]=True
        parent[u]=v
        stack.append(u)
for v in reversed(order):
    p=parent[v]
    if p==-1:
        continue
    if len(merged[v])>len(merged[p]):
        merged[v],merged[p]=merged[p],merged[v]
    for x in merged[v]:
        merged[p].add(x)
# merged[root] contains union of all values
#
    parent=[-1]*(n+1)
    order =[]
    visited= [False]*(n+1)
    stack =[root]
    visited[root]=True
    while stack:
        v=stack[-1]
        pushed=False
        for u in adj[v]:
            if not visited[u]:
                visited[u]=True
                parent[u]=v
                stack.append(u)
                pushed=True
                break
        if not pushed:
            order.append(stack.pop())
#
    for v in order:
        if parent[v] == -1:
            continue
        p=parent[v]
#
# ┌────────────────────────────────────────────────────────────────────────────┐
        # Merge smaller into larger
# └────────────────────────────────────────────────────────────────────────────┘
#
#
        if len(sets[p]) < len(sets[v]):
            sets[p], sets[v]=sets[v], sets[p]
        sets[p] |= sets[v]
#
    # return sets
