# ── convex_hull — inline ──
# DRY RUN — Convex hull on points:
#   Input: (0,0),(1,1),(2,0),(1,2),(0,2),(2,2)
#   Sorted: (0,0),(0,2),(1,1),(1,2),(2,0),(2,2)
#
#   Lower hull (left to right):
#     add (0,0): lower=[(0,0)]
#     add (0,2): lower=[(0,0),(0,2)]
#     add (1,1): cross((0,0),(0,2),(1,1))=(0-0)*(1-0)-(2-0)*(1-0)=-2<=0
#       pop (0,2). lower=[(0,0),(1,1)]
#     add (1,2): lower=[(0,0),(1,1),(1,2)]
#     add (2,0): cross((1,1),(1,2),(2,0))=(0)*(-1)-(1)*(1)=-1<=0
#       pop (1,2). cross((0,0),(1,1),(2,0))=(1)*(-1)-(1)*(2)=-3<=0
#       pop (1,1). lower=[(0,0),(2,0)]
#     add (2,2): lower=[(0,0),(2,0),(2,2)]
#   Lower = [(0,0),(2,0),(2,2)]
#
#   Upper hull: similar process from right to left -> (1,2),(0,2)
#   Hull = [(0,0),(2,0),(2,2),(1,2),(0,2)]
# DEBUG CHECKLIST — Convex Hull:
#   1. Sort points lexicographically (by x, then y).
#   2. Cross product <= 0 removes collinear points (use < 0 to keep them).
#   3. Monotone chain produces CCW hull. Reverse for CW.
#   4. Result excludes duplicate start/end point (lower[:-1] + upper[:-1]).
#   5. For floating-point input, add epsilon to cross product comparison.
pts=sorted(set(points))
count_n=len(pts)
if count_n<=1:
    hull=pts
else:
    lower=[]
    for p in pts:
        while len(lower)>=2 and (
            (lower[-1][0]-lower[-2][0])*(p[1]-lower[-2][1])
           -(lower[-1][1]-lower[-2][1])*(p[0]-lower[-2][0])<=0):
            lower.pop()
        lower.append(p)
    upper=[]
    for p in reversed(pts):
        while len(upper)>=2 and (
            (upper[-1][0]-upper[-2][0])*(p[1]-upper[-2][1])
           -(upper[-1][1]-upper[-2][1])*(p[0]-upper[-2][0])<=0):
            upper.pop()
        upper.append(p)
    hull=lower[:-1]+upper[:-1]
# result→hull
#
# ┌────────────────────────────────────────────────────────────────────────────┐
    # Build lower hull
# └────────────────────────────────────────────────────────────────────────────┘
#
#
    lower=[]
    for p in pts:
        while len(lower) >= 2 and cross(lower[-2], lower[-1], p) <= 0:
            lower.pop()
        lower.append(p)
#
# ┌────────────────────────────────────────────────────────────────────────────┐
    # Build upper hull
# └────────────────────────────────────────────────────────────────────────────┘
#
#
    upper=[]
    for p in reversed(pts):
        while len(upper) >= 2 and cross(upper[-2], upper[-1], p) <= 0:
            upper.pop()
        upper.append(p)
#
    # return lower[:-1]+upper[:-1]
#

