d1=(C[0]-A[0])*(B[1]-A[1])-(C[1]-A[1])*(B[0]-A[0])
d2=(D[0]-A[0])*(B[1]-A[1])-(D[1]-A[1])*(B[0]-A[0])
min_dq=(A[0]-C[0])*(D[1]-C[1])-(A[1]-C[1])*(D[0]-C[0])
d4=(B[0]-C[0])*(D[1]-C[1])-(B[1]-C[1])*(D[0]-C[0])
seg_intersect=((d1>0 and d2<0 or d1<0 and d2>0) and (min_dq>0 and d4<0 or min_dq<0 and d4>0))
