# ── polygon_area_exact — inline ──
exact_area=0
n_pts=len(pts)
for i in range(n_pts):
    j=(i+1)%n_pts
    exact_area+=pts[i][0]*pts[j][1]-pts[j][0]*pts[i][1]
exact_area=abs(exact_area)
# result→_pae (= 2*area, integer for integer coords)
