# ── point_in_polygon_ray — inline ──
is_inside=False
count_n=len(poly)
j=count_n-1
for i in range(count_n):
    xi=poly[i][0]
    yi=poly[i][1]
    xj=poly[j][0]
    yj=poly[j][1]
    if ((yi>P[1])!=(yj>P[1])) and (P[0]<(xj-xi)*(P[1]-yi)/(yj-yi)+xi):
        is_inside=not is_inside
    j=i
# result→_inside
