# ── point_on_segment_geo — inline ──
cross_val=(P[0]-A[0])*(B[1]-A[1])-(P[1]-A[1])*(B[0]-A[0])
in_range_x=min(A[0],B[0])<=P[0]<=max(A[0],B[0])
in_range_y=min(A[1],B[1])<=P[1]<=max(A[1],B[1])
on_seg=(cross_val==0 and in_range_x and in_range_y)
# result→_on_seg
#

# ── dist_point_to_segment — inline ──
dx=B[0]-A[0]
dy=B[1]-A[1]
len2=dx**2+dy**2
if len2==0:
    dps=((P[0]-A[0])**2+(P[1]-A[1])**2)**0.5
else:
    target=max(0,min(1,((P[0]-A[0])*dx+(P[1]-A[1])*dy)/len2))
    dps=((P[0]-A[0]-target*dx)**2+(P[1]-A[1]-target*dy)**2)**0.5
# result→_dps
#

# ── line_intersection_geo — inline ──
a1=B[1]-A[1]
b1=A[0]-B[0]
c1=a1*A[0]+b1*A[1]
mat_a=D[1]-C[1]
mat_b=C[0]-D[0]
c2=mat_a*C[0]+mat_b*C[1]
determinant=a1*mat_b-mat_a*b1
if determinant==0:
    line_inter_pt=None
else:
    line_inter_pt=((c1*mat_b-c2*b1)/determinant,(a1*c2-mat_a*c1)/determinant)
# result→_lig
#

# ── polygon_perimeter — inline ──
perimeter=0
for i in range(len(pts)):
    dx=pts[(i+1)%len(pts)][0]-pts[i][0]
    dy=pts[(i+1)%len(pts)][1]-pts[i][1]
    perimeter+=(dx*dx+dy*dy)**0.5
# result→_pp
#
# WHAT: O(n) algorithms on a convex hull for farthest-pair and min rectangle.
#

# ── hull_diameter — inline ──
count_n=len(hull)
hull_diam=0
j=1
for i in range(count_n):
    while True:
        cx1=hull[(i+1)%count_n][0]-hull[i][0]
        cy1=hull[(i+1)%count_n][1]-hull[i][1]
        nj=(j+1)%count_n
        cx2=hull[nj][0]-hull[j][0]
        cy2=hull[nj][1]-hull[j][1]
        if cx1*cy2-cy1*cx2>0:
            j=nj
        else:
            break
    d2=(hull[i][0]-hull[j][0])**2+(hull[i][1]-hull[j][1])**2
    if d2>hull_diam:
        hull_diam=d2
# result→_hdiam (squared diameter; take sqrt for actual distance)
#

# ── min_bounding_rect_area — inline ──
count_n=len(hull)
min_rect_area=float("inf")
for i in range(count_n):
    ex=hull[(i+1)%count_n][0]-hull[i][0]
    ey=hull[(i+1)%count_n][1]-hull[i][1]
    seg_len=(ex**2+ey**2)**0.5
    if seg_len==0:
        continue
    ex/=seg_len
    ey/=seg_len
    rotated_pts=[(p[0]*ex+p[1]*ey,p[0]*(-ey)+p[1]*ex) for p in hull]
    min_x=min(p[0] for p in rotated_pts)
    max_x=max(p[0] for p in rotated_pts)
    min_y=min(p[1] for p in rotated_pts)
    max_y=max(p[1] for p in rotated_pts)
    area_val=(max_x-min_x)*(max_y-min_y)
    if area_val<min_rect_area:
        min_rect_area=area_val
# result→_min_rect
#
