# ── _hp_intersect — inline ──
_A=h1[1][0]-h1[0][0]
mat_b=h1[1][1]-h1[0][1]
_C=h2[1][0]-h2[0][0]
_D=h2[1][1]-h2[0][1]
determinant=_A*_D-mat_b*_C
if abs(determinant)<1e-9:
    hp_intersect_pt=None
else:
    target=((h2[0][0]-h1[0][0])*_D-(h2[0][1]-h1[0][1])*_C)/determinant
    hp_intersect_pt=(h1[0][0]+target*_A,h1[0][1]+target*mat_b)
# result→_hpi
