# ── half_plane_intersection — inline ──
import math as mth5
half_planes=sorted(half_planes,
    key=lambda h:mth5.atan2(h[1][1]-h[0][1],h[1][0]-h[0][0]))
# Deque-based half-plane intersection (O(n log n))
dq=[]
for h in half_planes:
    while len(dq)>=2:
        _A=dq[-2][1][0]-dq[-2][0][0]
        mat_b=dq[-2][1][1]-dq[-2][0][1]
        _C=dq[-1][1][0]-dq[-1][0][0]
        _D=dq[-1][1][1]-dq[-1][0][1]
        determinant=_A*_D-mat_b*_C
        if abs(determinant)<1e-9:
            dq.pop()
        break
        target=((h[0][0]-dq[-2][0][0])*_D-(h[0][1]-dq[-2][0][1])*_C)/determinant
        pt=(dq[-2][0][0]+target*_A,dq[-2][0][1]+target*mat_b)
        half_cross=(h[1][0]-h[0][0])*(pt[1]-h[0][1])-(h[1][1]-h[0][1])*(pt[0]-h[0][0])
        if half_cross<0:
            dq.pop()
        else:
            break
    dq.append(h)
hpi_result=dq  # remaining half-planes form the intersection
# result→hpi_result
