# ── interior_lattice_points — inline ──
from math import gcd as gcd_fn
mat_b=0
for i in range(len(poly_int)):
    dx=abs(poly_int[(i+1)%len(poly_int)][0]-poly_int[i][0])
    dy=abs(poly_int[(i+1)%len(poly_int)][1]-poly_int[i][1])
