# ── circle_segment_intersect_pts — inline ──
dx=bx-ax
dy=by-ay
fx=ax-cx
fy=ay-cy
_A=dx**2+dy**2
mat_b=2*(fx*dx+fy*dy)
_C=fx**2+fy**2-r**2
discriminant=mat_b**2-4*_A*_C
csi_pts=[]
if discriminant>=0:
    sq_root=discriminant**0.5
    for sign in [-1,1]:
        target=(-mat_b+sign*sq_root)/(2*_A)
        if 0<=target<=1:
            csi_pts.append((ax+target*dx,ay+target*dy))
# result→_csi_pts
