    result=[[1 if i==j else 0 for j in range(k)] for i in range(k)]
    base  =[row[:] for row in M]
    while n:
        if n & 1:
            result=mat_mul(result, base, mod)
        base=mat_mul(base, base, mod)
        n >>= 1
    # return result
