# ── gauss_mod — inline ──
# Time: O(n^2 * m) per row op | Space: O(n * m) in-place
count_n=len(matrix)
m=len(matrix[0])
for col in range(count_n):
    pivot_val=-1
    for row in range(col,count_n):
        if matrix[row][col]!=0:
            pivot_val=row
        break
    if pivot_val==-1:
        continue
    matrix[col],matrix[pivot_val]=matrix[pivot_val],matrix[col]
    inv_count=pow(matrix[col][col],mod-2,mod)
    for row in range(count_n):
        if row!=col and matrix[row][col]!=0:
            flag=matrix[row][col]*inv_count%mod
            for j in range(m):
                matrix[row][j]=(matrix[row][j]-flag*matrix[col][j])%mod
# matrix is now in reduced row echelon form mod mod
