# When problem asks for E[X] mod p (p prime):
# Represent probabilities as fractions a/b, answer as a * b^{-1} mod p.
# All operations done mod p. Division = multiply by modular inverse.
#
MOD = 10**9 + 7
#
# inv(x,mod): pow(x,mod-2,mod)
#

# ── expected_swaps_bubble_sort — inline ──
# E[swaps] = E[inversions] = n*(n-1)/4 (for random permutation)
esb=n*(n-1)*pow(4,mod-2,mod)%mod
# result→_esb
#
# ┌────────────────────────────────────────────────────────────────────────────┐
    # E[swaps] = n*(n-1)/4 mod p
# └────────────────────────────────────────────────────────────────────────────┘
#
#
    # return n*(n-1)%mod*inv(4, mod)%mod
#

# ── expected_distinct_after_k_draws — inline ──
# E[distinct] after k draws from n items (with replacement)
# = n*(1-(1-1/n)^k) ≈ n*(1-((n-1)/n)^k)
ed=n*((1-pow(pow(n,mod-2,mod),k,mod))%mod)%mod
# result→_ed
#

# ── expected_steps_random_walk — inline ──
# E[steps to visit all n nodes] = Coupon collector = n*H(n) where H=harmonic
ew=0
for i in range(1,n+1):
    ew=(ew+n*pow(i,mod-2,mod))%mod
# result→_ew
#

# ── prob_sum_exactly_s — inline ──
# P(sum of n_dice dice each with [1..faces] == target)
dp=[0]*(target+1)
dp[0]=1
for _ in range(n_dice):
    new_dp=[0]*(target+1)
    for node_v in range(1,faces+1):
        for val_x in range(target+1-node_v):
            new_dp[val_x+node_v]=(new_dp[val_x+node_v]+dp[val_x])%mod
    dp=new_dp
prob_ss=dp[target]
# result→_pss
# PROBABILITY COMMON MISTAKES:
# 1. Confusing E[X²] with E[X]² — they are NOT equal (Jensen's inequality).
# 2. Forgetting that linearity of expectation works even for DEPENDENT variables.
# 3. For "mod prime" problems: P = 0 is fine, but division (inv) of 0 is undefined.
# 4. Cycle detection in probability DP — set up equations and solve (Gaussian elim).
# 5. "Expected value" and "probability" are different — read the problem carefully.
