# ══════════════════════════════════════════════════════════════════════════════
# ADVANCED STRING ALGORITHMS — Suffix Automaton, Palindromic Tree, Manacher
# ══════════════════════════════════════════════════════════════════════════════

# ── MANACHER'S ALGORITHM — All palindromic substrings in O(n) ─────────────────
# p[i] = radius of longest palindrome centred at i (in transformed string)
# Transforms s into '#a#b#a#' format to handle even-length palindromes uniformly
# Time: O(n)  Space: O(n)
#
# DRY RUN on "abacaba":
#   Transformed: #a#b#a#c#a#b#a#
#   p[]:          0101012101 0 1 0
#   p[7]=6 means palindrome "abacaba" (radius 6 in transformed = radius 3 in original)
#
man_str = '#' + '#'.join(s_manacher) + '#'
man_n = len(man_str)
man_p = [0]*man_n
man_center = man_right = 0
for i in range(man_n):
    if i < man_right:
        man_p[i] = min(man_right - i, man_p[2*man_center - i])
    while (i - man_p[i] - 1 >= 0
           and i + man_p[i] + 1 < man_n
           and man_str[i-man_p[i]-1] == man_str[i+man_p[i]+1]):
        man_p[i] += 1
    if i + man_p[i] > man_right:
        man_center = i
        man_right = i + man_p[i]
# _mn_p[i] = radius of palindrome centred at position i in transformed string
# Longest palindromic substring length = max(_mn_p)
# Longest palindrome in original: center=(argmax-1)//2, length=max(_mn_p)
best_idx = man_p.index(max(man_p))
pal_start = (best_idx - man_p[best_idx]) // 2
