#         for b in range(bl+1, br):
#             res += self.block[b]
#         res += sum(self.a[br*self.B : r+1])
#         return res
#
# HEAVY-LIGHT SQRT TRICK (for DS on trees / offline):
#   • "Heavy" nodes: degree ≥ √n. At most √n of them.
#   • "Light" nodes: degree < √n.
#   • Process heavy and light nodes separately in O(n√n) total.
#   • Classic use: "sum of subtree sizes" optimizations, small-to-large merging.
#
# KEY PROBLEMS:
#   CF 380C — Sereja and Brackets                        [1800]  sqrt + stack
#   CF 786C — Till I Collapse                            [2200]  sqrt + offline
#   CF 940F — Machine Learning                           [2400]  Mo's with updates (√n blocks)
