# 🧠 27E. D&C DP — DIVIDE & CONQUER OPTIMISATION  [DP]

# ──────────────────────────────────────────────────────────────────────────────
#
# When: dp[i][j] = min over k≤j of { dp[i-1][k] + cost(k+1, j) }
#       AND opt(i, j-1) ≤ opt(i, j) ≤ opt(i+1, j)   (monotone optimal split)
# Then D&C reduces O(n²) per layer to O(n log n).
#
# ── dnc_dp_layer — D&C DP layer (divide and conquer DP) ──
# Solves dp[cur][j] = min over k<=j of (prev[k] + cost(k,j))
# with monotone optimal k. O(n log n) per layer.
# dc(lo,hi,optlo,opthi):
#   if lo>hi: return
#   mid=(lo+hi)//2; best=INF; opt=optlo
#   for k in range(optlo,min(opthi,mid)+1):
#     val=prev[k]+cost(k,mid)
#     if val<best: best=val; opt=k
#   dp_cur[mid]=best
#   dc(lo,mid-1,optlo,opt); dc(mid+1,hi,opt,opthi)
# Call iteratively using explicit stack to avoid recursion:
dc_stack=[(0,n-1,0,n-1)]
while dc_stack:
    lo,hi,opt_lo,opt_hi=dc_stack.pop()
    if lo>hi:
        continue
    mid=(lo+hi)//2
    best=float('inf')
    opt_k=opt_lo
    for k in range(opt_lo,min(opt_hi,mid)+1):
        val=prev[k]+cost(k,mid)
        if val<best:
            best=val
        opt_k=k
    dp_cur[mid]=best
    dc_stack.append((lo,mid-1,opt_lo,opt_k))
    dc_stack.append((mid+1,hi,opt_k,opt_hi))
#
# ⚡ Complexity: O(n log n) per DP layer.  [DP]

