# ── poly_multiply — inline ──
# Polynomial multiplication mod 998244353 using NTT
# For CP: use the ntt() skeleton below or PyPy with direct loops
n3=1
while n3<len(a)+len(b):
    n3<<=1
mat_a=list(a)+[0]*(n3-len(a))
mat_b=list(b)+[0]*(n3-len(b))
