# ══════════════════════════════════════════════════════════════════════════════
# 🧠  THE CORE IDENTITIES (all O(1) given precomputed fib)
# ══════════════════════════════════════════════════════════════════════════════
#
#   Standard def: F(0)=0, F(1)=1, F(2)=1, F(3)=2, F(4)=3, F(5)=5, ...
#
#   ⚡ SUM IDENTITIES (memorize these — they appear in O(1) reductions):
#
#     1. Sum of first n Fibonacci:
#            F(1)+F(2)+...+F(n) = F(n+2) - 1
#
#     2. Sum of first n with even index:
#            F(2)+F(4)+...+F(2n) = F(2n+1) - 1
#
#     3. Sum of first n with odd index:
#            F(1)+F(3)+...+F(2n-1) = F(2n)
#
#     4. Sum of squares:
#            F(1)²+F(2)²+...+F(n)² = F(n)*F(n+1)
#
#     5. Cassini's Identity:
#            F(n-1)*F(n+1) - F(n)² = (-1)^n
#
#     6. GCD identity:
#            gcd(F(m), F(n)) = F(gcd(m, n))
#
#     7. Multiplication identity:
#            F(m+n) = F(m)*F(n+1) + F(m-1)*F(n)
#
# 🎯 SIGNALS:
#   • "sum of Fibonacci numbers up to index n" → identity 1 above, O(1)
#   • "gcd of two Fibonacci numbers"           → identity 6 above
#   • "is n a Fibonacci number?"               → check if 5n²±4 is a perfect square

# ══════════════════════════════════════════════════════════════════════════════
# 🚀 IMPLEMENTATIONS
# ══════════════════════════════════════════════════════════════════════════════

# Fast Fibonacci via matrix exponentiation (O(log n)) — basis for everything below
#

# ── fib_pair — inline ──
# Returns (fib(n), fib(n+1)) using fast matrix doubling  O(log n)
# Uses identities: fib(2k)=fib(k)*(2*fib(k+1)-fib(k)), fib(2k+1)=fib(k)^2+fib(k+1)^2
fib_a, fib_b = 0, 1  # fib(0), fib(1)
fib_n = n
fib_bits = []
while fib_n:
    fib_bits.append(fib_n & 1)
    fib_n >>= 1
for fib_bit in reversed(fib_bits[:
    -1]):
    fib_c = fib_a * (2 * fib_b - fib_a) % mod
    fib_d = (fib_a * fib_a + fib_b * fib_b) % mod
    fib_a, fib_b = fib_c, fib_d
    if fib_bit:
        fib_a, fib_b = fib_b, (fib_a + fib_b) % mod
fib_pair_result = (fib_a, fib_b)
# result→_fp (fib(n), fib(n+1))


# ── fib — inline ──
# NOTE: requires `mod` to be set (e.g. mod=10**9+7)
if n==0:
    fib_result=0
elif n==1:
    fib_result=1
else:
    mat=[[1,1],[1,0]]
    result_mat=[[1,0],[0,1]]
    exp=n-1
    while exp:
        if exp&1:
            temp_mat=[
                [(result_mat[0][0]*mat[0][0]+result_mat[0][1]*mat[1][0])%mod,
                 (result_mat[0][0]*mat[0][1]+result_mat[0][1]*mat[1][1])%mod],
                [(result_mat[1][0]*mat[0][0]+result_mat[1][1]*mat[1][0])%mod,
                 (result_mat[1][0]*mat[0][1]+result_mat[1][1]*mat[1][1])%mod]]
            result_mat=temp_mat
        temp_mat2=[
            [(mat[0][0]**2+mat[0][1]*mat[1][0])%mod,
             (mat[0][0]*mat[0][1]+mat[0][1]*mat[1][1])%mod],
            [(mat[1][0]*mat[0][0]+mat[1][1]*mat[1][0])%mod,(mat[1][0]*mat[0][1]+mat[1][1]**2)%mod]]
        mat=temp_mat2
        exp>>=1
    fib_result=result_mat[0][0]
# result→_fb


