from math import gcd as gcd_val
fib_prefix_sum=0
a3,b3=0,1
for _ in range(n+2):
    fib_prefix_sum=(fib_prefix_sum+a3)%mod
a3,b3=b3,(a3+b3)%mod
fib_prefix_sum=(b3-1)%mod
# result→_fps (sum fib(0)+...+fib(n) = fib(n+2)-1)


