# ══════════════════════════════════════════════════════════════════════════════
# ⚡ PISANO PERIOD — period of F(n) mod m
# ══════════════════════════════════════════════════════════════════════════════
#
# F(n) mod m is purely periodic (the Pisano period π(m)).
#   π(2)=3, π(3)=8, π(5)=20, π(10)=60, π(10⁹+7)=2*(10⁹+7)+...
# Key property: π(m) always ends with ...01 (F(π(m)-1)≡0, F(π(m))≡1 mod m).
# Use: F(n) mod m = F(n mod π(m)) mod m — can reduce n = 10^(10^18) to small index.
#
# ⚠️ Finding π(m) naively is O(m²) — only feasible for small m.
#    For large prime p: π(p) divides 2(p−1) or 2(p+1) (use this to bound search).

# ── pisano_period — inline ──
mat_a,mat_b=0,1
perimeter=0
for perimeter in range(1,6*m+5):
    mat_a,mat_b=mat_b,(mat_a+mat_b)%m
    if mat_a==0 and mat_b==1:
        break
# result→_pp


# ── fib_huge — inline ──
mod2=mod
cur_sum=n_str
result=0
base_val=10
cur=0
for cycle_count in cur_sum:
    cur=(cur*base_val+int(cycle_count))%mod2  # not the period approach; just eval n mod period
mat_a,mat_b=0,1
for _ in range(cur):
    mat_a,mat_b=mat_b,(mat_a+mat_b)%mod2
fh=mat_a
# result→_fh (approximate; for exact use Pisano period)
# ══════════════════════════════════════════════════════════════════════════════
# ⚡ ZECKENDORF'S THEOREM — greedy Fibonacci representation  [GREEDY]

# ══════════════════════════════════════════════════════════════════════════════
#
# Every positive integer n has a UNIQUE representation as a sum of
# NON-CONSECUTIVE Fibonacci numbers.  (Like binary, but Fibonacci base.)
# Greedy: always pick the largest Fibonacci ≤ n, subtract, repeat.
#
# 💡 Use case in CP:
#   • "minimum number of Fibonacci numbers summing to n" → Zeckendorf count.
#   • Fibonacci coding, Fibonacci number system.

# ── zeckendorf — inline ──
fibs=[1,2]
while fibs[-1]<n:
    fibs.append(fibs[-1]+fibs[-2])
zk=[]
remaining=n
for flag in reversed(fibs):
    if flag<=remaining:
        zk.append(flag)
    remaining-=flag
# result→_zk (Zeckendorf representation: list of Fibonacci numbers)


# ── is_fibonacci — inline ──
import math as mth
is_square_fn=lambda x: mth.isqrt(x)**2==x
is_fib=is_square_fn(5*n*n+4) or is_square_fn(5*n*n-4)
# result→_ifib
