# ══════════════════════════════════════════════════════════════════════════════
# 🧠 MÖBIUS FUNCTION μ(n)
# ══════════════════════════════════════════════════════════════════════════════
#
# μ(1) = 1
# μ(n) = 0         if n has a squared prime factor
# μ(n) = (-1)^k    if n is a product of k distinct primes
#
# WHY IT MATTERS:
#   Möbius inversion: if g(n) = Σ_{d|n} f(d), then f(n) = Σ_{d|n} μ(n/d)*g(d).
#   This transforms "sums over divisors" problems.
#
# KEY APPLICATION: count coprime pairs, squarefree numbers, gcd-related sums.
#
# 🎯 SIGNALS:
#   • "count pairs (i,j) with gcd(i,j) = 1"
#   • "sum over gcd = k"
#   • "squarefree numbers up to n"

# ── mobius_sieve — inline ──
mu=[0]*(n+1)
mu[1]=1
prime_list2=[]
is_prime2=[True]*(n+1)
for i in range(2,n+1):
    if is_prime2[i]:
        prime_list2.append(i)
    mu[i]=-1
    for p in prime_list2:
        if i*p>n:
            break
        is_prime2[i*p]=False
        if i%p==0:
            mu[i*p]=0
        break
        mu[i*p]=-mu[i]
# result→mu (Möbius function)


# ── phi_sieve_linear — inline ──
phi2=[0]*(n+1)
phi2[1]=1
prime_list3=[]
is_prime3=[True]*(n+1)
for i in range(2,n+1):
    if is_prime3[i]:
        prime_list3.append(i)
    phi2[i]=i-1
    for p in prime_list3:
        if i*p>n:
            break
        is_prime3[i*p]=False
        if i%p==0:
            phi2[i*p]=phi2[i]*p
        break
        phi2[i*p]=phi2[i]*(p-1)
# result→phi2


# ── sum_phi_to_n — inline ──
# Sum of phi(1)+...+phi(n) using formula S(n)=(n*(n+1)//2 - sum(S(n//k) for k=2..n))/1
# Simple sieve approach for moderate n
phi3=list(range(n+1))
for i in range(2,n+1):
    if phi3[i]==i:
        for j in range(i,n+1,i):
            phi3[j]-=phi3[j]//i
sphi=sum(phi3[1:n+1])
# result→_sphi
# ══════════════════════════════════════════════════════════════════════════════
# 🚀 COPRIME PAIR COUNTING using Möbius  [GRAPH]

# ══════════════════════════════════════════════════════════════════════════════
#
# Count pairs (i,j) with 1≤i,j≤n and gcd(i,j)=1:
#   Answer = 2 * Σ_{k=1}^{n} μ(k) * ⌊n/k⌋² - 1
# (subtract 1 for the pair (1,1) counted once, or adjust based on problem.)
#
# More general: count pairs with gcd = d in [1,A]×[1,B]:
#   = Σ_{k=1}^{min(A,B)/d} μ(k) * ⌊A/(dk)⌋ * ⌊B/(dk)⌋

# ── count_coprime_pairs — inline ──
# Count pairs (i,j) 1<=i<j<=n with gcd(i,j)=1
# = (sum_{k=1}^n phi(k) * (something)) — use Euler phi sieve
phi4=list(range(n+1))
for i in range(2,n+1):
    if phi4[i]==i:
        for j in range(i,n+1,i):
            phi4[j]-=phi4[j]//i
coprime_count=sum(phi4[1:n+1])-1  # pairs: (sum phi - 1) for pairs with gcd=1
# result→_ccp (approximate — exact formula depends on problem definition)
