# ╔════════════════════════════════════════════════════════════════════════════╗
# ║           BONUS U — SUM OF GCD(i, n) FOR i = 1..n  (PHI TRICK)           ║
# ╚════════════════════════════════════════════════════════════════════════════╝

# ══════════════════════════════════════════════════════════════════════════════
# 🧠 FORMULA
# ══════════════════════════════════════════════════════════════════════════════
#
#   Σᵢ₌₁ⁿ gcd(i, n)  =  Σ_{d | n}  d * φ(n/d)
#
# PROOF SKETCH:
#   Group the sum by the value of gcd(i,n) = d.
#   The number of i in [1,n] with gcd(i,n) = d is φ(n/d).
#   So the total contribution from divisor d is d * φ(n/d).
#
# COMPLEXITY: O(sqrt(n)) per query (enumerate divisors, compute φ).
#
# 🎯 SIGNALS:
#   • "sum of gcd(i,n) for i in 1..n"
#   • "Euler phi over divisors"
#   • Appears in counting problems and necklace variants

# ── sum_gcd_with_n — inline ──
# sum of gcd(i,n) for i=1..n = sum_{d|n} d*phi(n/d)
sum_gcd_n=0
i=1
while i*i<=n:
    if n%i==0:
        # phi(n/_i) and phi(n/(_i))
        def phi_single(x):
            prime=x
            tmp_val=x
            d2=2
            while d2*d2<=tmp_val:
                if tmp_val%d2==0:
                    while tmp_val%d2==0:
                        tmp_val//=d2
                    prime-=prime//d2
                d2+=1
            if tmp_val>1:
                prime-=prime//tmp_val
            return prime
        sum_gcd_n+=i*phi_single(n//i)
        if i!=n//i:
            sum_gcd_n+=(n//i)*phi_single(i)
    i+=1
# result→_sgn


# ── sum_gcd_range — inline ──
# sum of gcd(a_arr[i], n) for all i
sum_gcd_result=0
for val_x in a_arr:
    gcd_val=val_x
    tmp_val=n
    while tmp_val:
        gcd_val,tmp_val=tmp_val,gcd_val%tmp_val  # gcd
    sum_gcd_result+=gcd_val
# result→_sgr
