#   d=1: 1*φ(6)=1*2=2
#   d=2: 2*φ(3)=2*2=4
#   d=3: 3*φ(2)=3*1=3
#   d=6: 6*φ(1)=6*1=6
#   Total = 2+4+3+6 = 15
#   Verify: gcd(1,6)+...+gcd(6,6) = 1+2+3+2+1+6 = 15 ✓
