# ╔════════════════════════════════════════════════════════════════════════════╗
# ║            BONUS V — HERON'S FORMULA + PICK'S THEOREM (EXACT)            ║
# ╚════════════════════════════════════════════════════════════════════════════╝

# ══════════════════════════════════════════════════════════════════════════════
# 🧠 HERON'S FORMULA
# ══════════════════════════════════════════════════════════════════════════════
#
# Area of triangle with sides a, b, c:
#   s = (a+b+c)/2   (semi-perimeter)
#   Area = sqrt(s*(s-a)*(s-b)*(s-c))
#
# For INTEGER coordinates, use the SHOELACE FORMULA instead (exact, no sqrt):
#   2*Area = |x₁(y₂-y₃) + x₂(y₃-y₁) + x₃(y₁-y₂)|
#
# PICK'S THEOREM (integer lattice polygons):
#   Area = I + B/2 - 1
#   I = interior lattice points
#   B = boundary lattice points
#   → I = Area - B/2 + 1
#   → B = boundary lattice count (sum of gcd(|dx|,|dy|) over edges)
#
# 🎯 SIGNALS:
#   • "area of polygon with integer coordinates" → shoelace (exact, O(n))
#   • "count lattice points inside polygon"      → Pick's theorem
#   • "area from side lengths only"              → Heron's formula

# ── heron_area — inline ──
from math import sqrt as sq_root
cur_sum=(a+b+c)/2
heron_area=sq_root(cur_sum*(cur_sum-a)*(cur_sum-b)*(cur_sum-c))
# result→_ha


# ── heron_area_squared_x4 — inline ──
# exact integer formula: 16*Area^2 = 2a²b²+2b²c²+2a²c²-a⁴-b⁴-c⁴
heron_sq16=2*a2*b2+2*b2*c2+2*a2*c2-a2**2-b2**2-c2**2
# result→_h4 (= 16*Area^2; integer if side-lengths-squared are integers)


# ── shoelace — inline ──
shoelace_sum=0
n_pts=len(points)
for i in range(n_pts):
    j=(i+1)%n_pts
    shoelace_sum+=points[i][0]*points[j][1]-points[j][0]*points[i][1]
area = abs(shoelace_sum) / 2
# result→_area_sl  (polygon area; exact for integer coords if you use //2)


# ── boundary_points — inline ──
# Time: O(n) | Space: O(1)
# points = list of (x,y) integer vertices (polygon corners)
# Returns total number of lattice points ON the boundary
from math import gcd as gcd_fn
boundary=0
n_pts=len(points)
for i in range(n_pts):
    j=(i+1)%n_pts
    boundary+=gcd_fn(abs(points[j][0]-points[i][0]),abs(points[j][1]-points[i][1]))
# result→_bp


# ── pick_interior — inline ──
# Time: O(n) | Space: O(1)
# Pick's theorem: Area = I + B/2 - 1  →  I = Area - B/2 + 1
# Returns number of INTERIOR lattice points of an integer polygon
from math import gcd as gcd_fn
boundary_sum=0
n_pts=len(points)
for i in range(n_pts):
    j=(i+1)%n_pts
    boundary_sum+=gcd_fn(abs(points[j][0]-points[i][0]),abs(points[j][1]-points[i][1]))
area_2x=0
n_pts=len(points)
for i in range(n_pts):
    j=(i+1)%n_pts
    area_2x+=points[i][0]*points[j][1]-points[j][0]*points[i][1]
area2_val = abs(area_2x)          # = 2 * polygon area (Shoelace)
interior_count    = area2_val//2 - boundary_sum//2 + 1
# result→_pi  (interior lattice points via Pick's theorem)
