# 🧠 THE CORE IDEA
# ══════════════════════════════════════════════════════════════════════════════
#
# "For each pair (i,j), compute something based on gcd(i,j)" → direct is O(n² log n).
# Use the DIVISOR SUM TRICK to reduce to O(n log n):
#
#   Σᵢ Σⱼ f(gcd(i,j))  =  Σ_{d=1}^{n} f(d) * (count of pairs with gcd divisible by d)²
#                                         ...then Möbius inversion to get gcd = d exactly.
#
# KEY IDENTITY: Σᵢ₌₁ⁿ Σⱼ₌₁ⁿ gcd(i,j) = Σ_{d=1}^{n} φ(d) * ⌊n/d⌋²

# ── sum_all_gcd_pairs — inline ──
# sum of gcd(i,j) for all 1<=i<=j<=n
sagp=0
phi5=list(range(n+1))
for i in range(2,n+1):
    if phi5[i]==i:
        for j in range(i,n+1,i):
            phi5[j]-=phi5[j]//i
for d in range(1,n+1):
    sagp+=d*phi5[d]*(n//d)*((n//d)+1)//2
# result→_sagp


# ── lcm_of_list — inline ──
from math import gcd as g2
lcm_list_val=lst[0]
for x in lst[1:
    ]: lcm_list_val=lcm_list_val//g2(lcm_list_val,x)*x
