# ── gcd_of_subarray_queries — inline ──
# Precompute GCD for range queries using sparse table
from math import gcd as g3
count_n=len(a)
_LOG=count_n.bit_length()
gst=[[0]*count_n for _ in range(_LOG)]
gst[0]=list(a)
for k in range(1,_LOG):
    for i in range(count_n-(1<<k)+1):
        gst[k][i]=g3(gst[k-1][i],gst[k-1][i+(1<<(k-1))])
log2t=[0]*(count_n+1)
for i in range(2,count_n+1):
    log2t[i]=log2t[i//2]+1
# gcd_query(l,r): k=_log2t[r-l+1]; gcd(_gst[k][l],_gst[k][r-(1<<k)+1])

# ── min_lcm_of_any_two — inline ──
from math import gcd as g4
a.sort()
min_lcm=float("inf")
for i in range(len(a)-1):
    z_left=a[i]//g4(a[i],a[i+1])*a[i+1]
    if z_left<min_lcm:
        min_lcm=z_left
